export enum MaintenanceStatus {
  Planned = 'P',
  Realized = 'R',
  None = 'N'
}

export interface MonthlyStatus {
  [month: string]: MaintenanceStatus;
}

export interface ScheduleEntry {
  id: number;
  equipo: string;
  modelo: string;
  actividad: string;
  respMantenimiento: string;
  respEquipo: string;
  frecuencia: string;
  status: MonthlyStatus;
}

export enum InventoryStatus {
  InUse = 'En Uso',
  InStorage = 'En Almacén',
  UnderMaintenance = 'En Mantenimiento',
  Decommissioned = 'De Baja'
}

export interface MaintenanceRecordHistory {
  id: string;
  date: string;
  type: 'Preventivo' | 'Correctivo' | 'Mejora' | 'Actividad';
  description: string;
  technician: string;
  details?: string; // Campo para el detalle manual
}

export interface ExtendedMaintenanceRecord extends MaintenanceRecordHistory {
  equipmentName: string;
  equipmentId: string;
}

export interface LifecycleData {
  characteristics: string;
  maintenanceHistory: MaintenanceRecordHistory[];
  usageHistory: string;
  observations: string;
}

export interface InventoryItem {
  id: string;
  name: string;
  category: string;
  model: string;
  serial: string;
  assignedTo: string;
  purchaseDate: string;
  status: InventoryStatus;
  imageUrl: string;
  lifecycle: LifecycleData;
}

import React, { useState, useRef, useEffect } from 'react';
import Logo from './Logo';
import { InventoryItem, MaintenanceRecordHistory } from '../types';

declare const html2canvas: any;
declare global {
  interface Window {
    jspdf: any;
  }
}

const initialFormData = {
  technicianName: 'Mauricio Pino',
  technicianId: '123456789',
  equipment: '',
  marcaModelo: '', // Ahora usado como "Detalle"
  maintenanceType: 'Preventivo',
  maintenanceDate: new Date().toISOString().split('T')[0],
  description: '',
  fechaFinalizacion: new Date().toISOString().split('T')[0],
  observations: '',
};

interface MaintenanceRecordProps {
  inventory: InventoryItem[];
  addMaintenanceToHistory: (itemId: string, historyEntry: MaintenanceRecordHistory) => void;
}

const MaintenanceRecord: React.FC<MaintenanceRecordProps> = ({ inventory, addMaintenanceToHistory }) => {
  const [formData, setFormData] = useState(() => {
    try {
      const savedData = localStorage.getItem('maintenanceRecordForm');
      return savedData ? JSON.parse(savedData) : initialFormData;
    } catch {
      return initialFormData;
    }
  });
  const [photo, setPhoto] = useState<string | null>(() => localStorage.getItem('maintenanceRecordPhoto'));
  const [selectedInventoryId, setSelectedInventoryId] = useState<string>('');

  const printRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem('maintenanceRecordForm', JSON.stringify(formData));
  }, [formData]);

  useEffect(() => {
    if (photo) {
      localStorage.setItem('maintenanceRecordPhoto', photo);
    } else {
      localStorage.removeItem('maintenanceRecordPhoto');
    }
  }, [photo]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleEquipmentSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const itemId = e.target.value;
    setSelectedInventoryId(itemId);
    const selectedItem = inventory.find(item => item.id === itemId);
    if (selectedItem) {
        setFormData(prev => ({
            ...prev,
            equipment: selectedItem.name,
            marcaModelo: selectedItem.model,
        }));
    } else {
         setFormData(prev => ({
            ...prev,
            equipment: '',
            marcaModelo: '',
        }));
    }
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setPhoto(event.target!.result as string);
      };
      reader.readAsDataURL(e.target.files[0]);
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  const handleExport = async () => {
    const { jsPDF } = window.jspdf;
    const element = printRef.current;
    if (element) {
      const canvas = await html2canvas(element, { scale: 2, useCORS: true });
      const data = canvas.toDataURL('image/png');

      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

      pdf.addImage(data, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`registro-mantenimiento-${formData.equipment.replace(/\s/g, '_') || 'nuevo'}.pdf`);
    }
  };

  const handleSaveDraft = () => {
    localStorage.setItem('maintenanceRecordForm', JSON.stringify(formData));
    if (photo) {
        localStorage.setItem('maintenanceRecordPhoto', photo);
    }
    alert('Borrador guardado exitosamente!');
  };

  const handleClearForm = () => {
    setFormData(initialFormData);
    setPhoto(null);
    setSelectedInventoryId('');
    localStorage.removeItem('maintenanceRecordForm');
    localStorage.removeItem('maintenanceRecordPhoto');
  };

  const handleFinalize = () => {
    if (!selectedInventoryId && !formData.equipment) {
        alert('Por favor, seleccione un equipo o ingrese el nombre de la actividad.');
        return;
    }
    if (!formData.description.trim()) {
        alert('Por favor, describa el mantenimiento realizado.');
        return;
    }
    const newHistoryEntry: MaintenanceRecordHistory = {
        id: `m-${Date.now()}`,
        date: formData.fechaFinalizacion,
        type: formData.maintenanceType as any,
        description: formData.description,
        technician: formData.technicianName,
        details: formData.marcaModelo,
    };

    // Si no hay ID seleccionado pero hay nombre, intentamos buscarlo o lo tratamos como registro manual
    const targetId = selectedInventoryId || 'MANUAL-ENTRY';
    addMaintenanceToHistory(targetId, newHistoryEntry);

    alert(`Mantenimiento registrado exitosamente.`);
    handleClearForm();
  };

  return (
    <div className="bg-white p-8 rounded-lg shadow-lg w-full max-w-4xl mx-auto">
      <div ref={printRef} className="p-8 bg-white">
        <div className="text-center mb-4">
          <Logo className="h-20 mx-auto" />
        </div>
        <div className="flex justify-between items-start mb-6">
          <div className="w-48" />
          <div className="text-center flex-grow">
            <h1 className="text-2xl font-bold text-gray-700">REGISTRO DE MANTENIMIENTO</h1>
          </div>
          <table className="border-collapse border border-gray-400 text-xs w-48">
            <tbody>
              <tr>
                <td className="border border-gray-400 p-1 font-bold bg-gray-100">CÓDIGO</td>
                <td className="border border-gray-400 p-1">RAD-06</td>
              </tr>
              <tr>
                <td className="border border-gray-400 p-1 font-bold bg-gray-100">VERSIÓN</td>
                <td className="border border-gray-400 p-1">01</td>
              </tr>
              <tr>
                <td className="border border-gray-400 p-1 font-bold bg-gray-100">VIGENCIA</td>
                <td className="border border-gray-400 p-1">09/08/2024</td>
              </tr>
            </tbody>
          </table>
        </div>

        <fieldset className="border border-gray-300 p-4 rounded-md mb-6">
          <legend className="text-lg font-semibold text-gray-600 px-2 uppercase">Datos del Técnico</legend>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Nombre:</label>
              <input type="text" name="technicianName" value={formData.technicianName} onChange={handleChange} className="mt-1 block w-full px-3 py-2 bg-gray-50 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500"/>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">No. de Identificación:</label>
              <input type="text" name="technicianId" value={formData.technicianId} onChange={handleChange} className="mt-1 block w-full px-3 py-2 bg-gray-50 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500"/>
            </div>
          </div>
        </fieldset>

        <fieldset className="border border-gray-300 p-4 rounded-md mb-6">
          <legend className="text-lg font-semibold text-gray-600 px-2 uppercase">Datos de la Actividad</legend>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Equipo o Actividad Principal:</label>
              <select 
                name="equipment" 
                value={selectedInventoryId} 
                onChange={handleEquipmentSelect} 
                className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500 mb-2"
              >
                  <option value="">Seleccione un equipo (Opcional)</option>
                  {inventory.map(item => <option key={item.id} value={item.id}>{item.name} - {item.id}</option>)}
              </select>
              <input 
                type="text" 
                name="equipment" 
                placeholder="O escriba el nombre de la actividad..." 
                value={formData.equipment} 
                onChange={handleChange} 
                className="block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Detalle:</label>
              <input 
                type="text" 
                name="marcaModelo" 
                value={formData.marcaModelo} 
                onChange={handleChange} 
                placeholder="Marca, modelo o detalles específicos..." 
                className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500"
              />
            </div>
          </div>
        </fieldset>

        <fieldset className="border border-gray-300 p-4 rounded-md mb-6">
          <legend className="text-lg font-semibold text-gray-600 px-2 uppercase">Descripción del Mantenimiento</legend>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <div>
              <label className="block text-sm font-medium text-gray-700">Tipo de Mantenimiento:</label>
              <select name="maintenanceType" value={formData.maintenanceType} onChange={handleChange} className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500">
                <option>Preventivo</option>
                <option>Correctivo</option>
                <option>Mejora</option>
                <option>Actividad</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700">Fecha de Elaboración:</label>
              <input type="date" name="maintenanceDate" value={formData.maintenanceDate} onChange={handleChange} className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500"/>
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700">Describa el mantenimiento realizado:</label>
            <textarea name="description" value={formData.description} onChange={handleChange} rows={4} className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500"></textarea>
          </div>
          <div className="mt-4">
             <input type="file" accept="image/*" ref={fileInputRef} onChange={handlePhotoChange} className="hidden" />
             <button onClick={triggerFileInput} className="px-4 py-2 text-sm bg-gray-200 text-gray-800 font-semibold rounded-lg hover:bg-gray-300">
                Adjuntar Evidencia Fotográfica
             </button>
             {photo && (
                <div className="mt-4 border p-2 rounded-lg inline-block">
                    <img src={photo} alt="Vista previa del mantenimiento" className="max-w-xs max-h-48 rounded"/>
                </div>
             )}
          </div>
           <div className="mt-4">
              <label className="block text-sm font-medium text-gray-700">Fecha de Finalización:</label>
              <input type="date" name="fechaFinalizacion" value={formData.fechaFinalizacion} onChange={handleChange} className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500"/>
            </div>
          <div className="mt-4">
            <label className="block text-sm font-medium text-gray-700">Observaciones Generales:</label>
            <textarea name="observations" value={formData.observations} onChange={handleChange} rows={3} className="mt-1 block w-full px-3 py-2 bg-white border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-green-500 focus:border-green-500"></textarea>
          </div>
        </fieldset>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mt-12 pt-8">
            <div className="text-center">
              <p className="font-cursive text-2xl text-gray-800" style={{fontFamily: "'Brush Script MT', cursive"}}>{formData.technicianName}</p>
              <hr className="border-t border-gray-400 mt-2"/>
              <p className="text-sm font-semibold text-gray-600 mt-2">ELABORÓ</p>
            </div>
            <div className="text-center h-16 border-b border-gray-400">
              <p className="text-sm font-semibold text-gray-600 mt-20">REVISÓ</p>
            </div>
            <div className="text-center h-16 border-b border-gray-400">
              <p className="text-sm font-semibold text-gray-600 mt-20">AUTORIZÓ</p>
