export default MaintenanceRecord;

import React, { useState, useMemo, useRef } from 'react';
import { ExtendedMaintenanceRecord, InventoryItem } from '../types';
import Logo from './Logo';

declare const html2canvas: any;
declare global {
  interface Window {
    jspdf: any;
  }
}

interface HistoryPanelProps {
  inventory: InventoryItem[];
}

const HistoryPanel: React.FC<HistoryPanelProps> = ({ inventory }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const printRef = useRef<HTMLDivElement>(null);

  const allRecords: ExtendedMaintenanceRecord[] = useMemo(() => {
    const records: ExtendedMaintenanceRecord[] = [];
    inventory.forEach(item => {
      item.lifecycle.maintenanceHistory.forEach(history => {
        records.push({
          ...history,
          equipmentName: item.name,
          equipmentId: item.id
        });
      });
    });
    // Sort by date descending
    return records.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [inventory]);

  const filteredRecords = useMemo(() => {
    return allRecords.filter(r => 
      r.equipmentName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.technician.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (r.details && r.details.toLowerCase().includes(searchTerm.toLowerCase()))
    );
  }, [allRecords, searchTerm]);

  const handleExportPDF = async () => {
    const { jsPDF } = window.jspdf;
    const element = printRef.current;
    if (element) {
      const canvas = await html2canvas(element, { scale: 2, useCORS: true });
      const data = canvas.toDataURL('image/png');

      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

      pdf.addImage(data, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`historial-actividades-calidad.pdf`);
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-lg w-full">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <h1 className="text-2xl font-bold text-gray-700">Historial de Actividades</h1>
        <div className="flex gap-2 w-full md:w-auto">
          <input
            type="text"
            placeholder="Buscar en el historial..."
            className="flex-grow p-2 border rounded-md shadow-sm focus:ring-green-500 focus:border-green-500"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <button 
            onClick={handleExportPDF}
            className="px-4 py-2 bg-green-700 text-white font-semibold rounded-lg shadow-md hover:bg-green-800 transition-colors whitespace-nowrap"
          >
            Exportar Reporte PDF
          </button>
        </div>
      </div>

      <div className="overflow-x-auto border rounded-lg shadow-sm" ref={printRef}>
        <div className="p-4 bg-white hidden print-header">
             <div className="flex justify-between items-center mb-6 border-b pb-4">
                <Logo className="h-12" />
                <div className="text-right">
                    <h2 className="text-xl font-bold text-gray-800">Reporte de Historial de Mantenimiento</h2>
                    <p className="text-sm text-gray-500">Fecha de generación: {new Date().toLocaleDateString()}</p>
                </div>
             </div>
        </div>
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Fecha</th>
              <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Equipo / Actividad</th>
              <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Detalle</th>
              <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Tipo</th>
              <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Descripción</th>
              <th className="px-4 py-3 text-left text-xs font-bold text-gray-500 uppercase tracking-wider">Técnico</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {filteredRecords.length > 0 ? filteredRecords.map((record) => (
              <tr key={record.id} className="hover:bg-gray-50">
                <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-900">{record.date}</td>
                <td className="px-4 py-3 text-sm font-medium text-green-700">{record.equipmentName}</td>
                <td className="px-4 py-3 text-sm text-gray-500">{record.details || 'N/A'}</td>
                <td className="px-4 py-3 whitespace-nowrap">
                  <span className={`px-2 py-1 text-xs font-semibold rounded-full 
                    ${record.type === 'Preventivo' ? 'bg-blue-100 text-blue-800' : 
                      record.type === 'Correctivo' ? 'bg-red-100 text-red-800' : 
                      'bg-purple-100 text-purple-800'}`}>
                    {record.type}
                  </span>
                </td>
                <td className="px-4 py-3 text-sm text-gray-600 max-w-xs truncate" title={record.description}>{record.description}</td>
                <td className="px-4 py-3 whitespace-nowrap text-sm text-gray-500">{record.technician}</td>
              </tr>
            )) : (
              <tr>
                <td colSpan={6} className="px-4 py-8 text-center text-gray-500">No se encontraron registros en el historial.</td>
              </tr>
            )}
          </tbody>
        </table>

        {/* Footer for PDF only */}
        <div className="mt-20 px-8 pb-8 flex justify-between hidden print-footer">
            <div className="text-center w-64 border-t border-gray-400 pt-2">
                <p className="text-xs font-bold text-gray-600">REVISADO POR</p>
            </div>
            <div className="text-center w-64 border-t border-gray-400 pt-2">
                <p className="text-xs font-bold text-gray-600">APROBADO POR</p>
            </div>
        </div>
      </div>

      <style>{`
        @media screen {
          .print-header, .print-footer { display: none; }
        }
        @media print {
          .print-header, .print-footer { display: block; }
          .no-print { display: none; }
        }
      `}</style>
    </div>
  );
};

