  { id: 2, equipo: 'Asistente comercial', modelo: '', actividad: 'Mtto Bios/Revision Cyber cloud', respMantenimiento: 'Mauricio Pino', respEquipo: 'Elsy campo', frecuencia: '30-45 dias', status: { ENERO: MaintenanceStatus.Planned, MARZO: MaintenanceStatus.Realized, JUNIO: MaintenanceStatus.Realized, AGOSTO: MaintenanceStatus.Realized, SEPTIEMBRE: MaintenanceStatus.Planned } },
