import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { ScheduleEntry, MaintenanceStatus, InventoryItem } from '../types';

declare const html2canvas: any;
declare global {
  interface Window {
    jspdf: any;
  }
}

const MONTHS = ['ENERO', 'FEBRERO', 'MARZO', 'ABRIL', 'MAYO', 'JUNIO', 'JULIO', 'AGOSTO', 'SEPTIEMBRE', 'OCTUBRE', 'NOVIEMBRE', 'DICIEMBRE'];

interface MaintenanceScheduleProps {
  schedule: ScheduleEntry[];
  setSchedule: React.Dispatch<React.SetStateAction<ScheduleEntry[]>>;
  inventory: InventoryItem[];
}

const MaintenanceSchedule: React.FC<MaintenanceScheduleProps> = ({ schedule, setSchedule, inventory }) => {

  const [newEntry, setNewEntry] = useState<{ inventoryId: string, actividad: string, respMantenimiento: string, frecuencia: string }>({ inventoryId: '', actividad: 'Revision Cyber Cloud', respMantenimiento: 'Mauricio Pino', frecuencia: '30-45 dias' });
  const [showAddForm, setShowAddForm] = useState(false);
  const printRef = useRef<HTMLDivElement>(null);

  const columnDefinitions = useMemo(() => [
    { id: 'equipo', label: 'Nombre de Equipo', minWidth: 150 },
    { id: 'modelo', label: 'Modelo/Serie', minWidth: 130 },
    { id: 'actividad', label: 'Actividad', minWidth: 150 },
    { id: 'respMantenimiento', label: 'Resp. Mantenimiento', minWidth: 130 },
    { id: 'respEquipo', label: 'Resp. equipo', minWidth: 130 },
    { id: 'frecuencia', label: 'Frecuencia', minWidth: 100 },
    ...MONTHS.map(month => ({ id: month, label: month, minWidth: 80 }))
  ], []);

  const [columnWidths, setColumnWidths] = useState<Record<string, number>>(() => {
    try {
        const savedWidths = localStorage.getItem('maintenanceScheduleColumnWidths');
        if (savedWidths) return JSON.parse(savedWidths);
    } catch (e) {}
    return columnDefinitions.reduce((acc, col) => {
        acc[col.id] = col.minWidth;
        return acc;
    }, {} as Record<string, number>);
  });

  useEffect(() => {
    localStorage.setItem('maintenanceScheduleColumnWidths', JSON.stringify(columnWidths));
  }, [columnWidths]);

  const resizingColumnRef = useRef<string | null>(null);
  const startXRef = useRef<number>(0);
  const startWidthRef = useRef<number>(0);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (resizingColumnRef.current) {
        const columnId = resizingColumnRef.current;
        const newWidth = startWidthRef.current + (e.clientX - startXRef.current);
        const columnDef = columnDefinitions.find(c => c.id === columnId);
        const minWidth = columnDef ? columnDef.minWidth : 50;

        if (newWidth >= minWidth) {
            setColumnWidths(prev => ({ ...prev, [columnId]: newWidth }));
        }
    }
  }, [columnDefinitions]);

  const handleMouseUp = useCallback(() => {
      resizingColumnRef.current = null;
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'default';
  }, [handleMouseMove]);

  const handleMouseDown = (e: React.MouseEvent, columnId: string) => {
      e.preventDefault();
      resizingColumnRef.current = columnId;
      startXRef.current = e.clientX;
      startWidthRef.current = columnWidths[columnId] || 0;
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
  };

  const handleStatusChange = (id: number, month: string) => {
    setSchedule(prevSchedule =>
      prevSchedule.map(entry => {
        if (entry.id === id) {
          const newStatus = { ...entry.status };
          const current = newStatus[month];
          if (current === MaintenanceStatus.Planned) {
            newStatus[month] = MaintenanceStatus.Realized;
          } else if (current === MaintenanceStatus.Realized) {
            delete newStatus[month];
          } else {
            newStatus[month] = MaintenanceStatus.Planned;
          }
          return { ...entry, status: newStatus };
        }
        return entry;
      })
    );
  };

  const handleEntryChange = (id: number, field: keyof ScheduleEntry, value: string) => {
    setSchedule(prevSchedule =>
      prevSchedule.map(entry => entry.id === id ? { ...entry, [field]: value } : entry)
    );
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    const selectedItem = inventory.find(i => i.id === newEntry.inventoryId);
    if (selectedItem && newEntry.actividad) {
      const newId = Math.max(...schedule.map(e => e.id), 0) + 1;
      const newScheduleEntry: ScheduleEntry = {
        id: newId,
        equipo: selectedItem.name,
        modelo: selectedItem.model,
        actividad: newEntry.actividad,
        respMantenimiento: newEntry.respMantenimiento,
        respEquipo: selectedItem.assignedTo,
        frecuencia: newEntry.frecuencia,
        status: {},
      };
      setSchedule([...schedule, newScheduleEntry]);
      setNewEntry({ inventoryId: '', actividad: 'Revision Cyber Cloud', respMantenimiento: 'Mauricio Pino', frecuencia: '30-45 dias' });
      setShowAddForm(false);
    } else {
      alert("Por favor, seleccione un equipo y complete la actividad.");
    }
  };

  const monthlyTotals = useMemo(() => {
    return MONTHS.map(month => {
      const planned = schedule.reduce((acc, entry) => acc + (Object.prototype.hasOwnProperty.call(entry.status, month) ? 1 : 0), 0);
      const realized = schedule.reduce((acc, entry) => acc + (entry.status[month] === MaintenanceStatus.Realized ? 1 : 0), 0);
      const compliance = planned > 0 ? (realized / planned) * 100 : 0;
      return { month, planned, realized, compliance };
    });
  }, [schedule]);

  const handleExport = async () => {
    const { jsPDF } = window.jspdf;
    const element = printRef.current;
    if (element) {
        const style = document.createElement('style');
        style.innerHTML = `
          table { font-size: 8px; border-collapse: collapse; }
          th, td { padding: 10px 4px !important; vertical-align: middle !important; }
          textarea { height: auto !important; min-height: 40px !important; overflow-y: hidden !important; border: none !important; resize: none !important; }
        `;
        element.appendChild(style);
        try {
            const canvas = await html2canvas(element, { scale: 3, useCORS: true });
            const data = canvas.toDataURL('image/png');
            const pdf = new jsPDF({ orientation: 'l', unit: 'mm', format: 'letter' });
            const margin = 10;
            const pdfWidth = pdf.internal.pageSize.getWidth();
            const imgWidth = pdfWidth - (margin * 2);
            const imgHeight = (canvas.height * imgWidth) / canvas.width;
            pdf.addImage(data, 'PNG', margin, margin, imgWidth, imgHeight);
            pdf.save(`programa-mantenimiento-vuelo.pdf`);
        } finally {
            element.removeChild(style);
        }
    }
  };

  const inputStyles = "bg-transparent w-full focus:outline-none focus:bg-gray-100 p-1 rounded";

  return (
    <div className="bg-white p-6 rounded-lg shadow-sm border w-full">
      <div ref={printRef}>
        <h1 className="text-2xl font-bold text-gray-800 mb-6">Programa de Mantenimientos Preventivos</h1>
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200 border table-fixed">
            <colgroup>
                {columnDefinitions.map(col => <col key={col.id} style={{ width: `${columnWidths[col.id]}px` }} />)}
            </colgroup>
            <thead className="bg-gray-50">
              <tr>
                {columnDefinitions.map(col => (
                  <th 
                    key={col.id} 
                    className={`px-2 py-3 text-xs font-bold text-gray-500 uppercase tracking-wider border-r relative ${MONTHS.includes(col.id) ? 'text-center' : 'text-left'}`}
                  >
                    {col.label}
                    <div onMouseDown={e => handleMouseDown(e, col.id)} className="absolute top-0 right-[-1px] h-full w-2 cursor-col-resize z-10 hover:bg-indigo-300 transition-colors" />
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {schedule.map(entry => (
                <tr key={entry.id} className="hover:bg-gray-50">
                  <td className="px-1 py-1 whitespace-normal text-sm font-medium text-gray-900 border-r align-top break-words">
                     <textarea value={entry.equipo} onChange={e => handleEntryChange(entry.id, 'equipo', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  <td className="px-1 py-1 whitespace-normal text-sm text-gray-500 border-r align-top break-words">
                     <textarea value={entry.modelo} onChange={e => handleEntryChange(entry.id, 'modelo', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  <td className="px-1 py-1 whitespace-normal text-sm text-gray-500 border-r align-top break-words">
                      <textarea value={entry.actividad} onChange={e => handleEntryChange(entry.id, 'actividad', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  <td className="px-2 py-2 whitespace-normal text-sm text-gray-500 border-r align-top break-words">
                    <textarea value={entry.respMantenimiento} onChange={e => handleEntryChange(entry.id, 'respMantenimiento', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  <td className="px-1 py-1 whitespace-normal text-sm text-gray-500 border-r align-top break-words">
                      <textarea value={entry.respEquipo} onChange={e => handleEntryChange(entry.id, 'respEquipo', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  <td className="px-2 py-2 whitespace-nowrap text-sm text-gray-500 border-r align-top">
                     <textarea value={entry.frecuencia} onChange={e => handleEntryChange(entry.id, 'frecuencia', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  {MONTHS.map(month => (
                    <td key={month} className="px-2 py-2 whitespace-nowrap text-sm text-gray-500 border-r text-center align-top">
                      <button onClick={() => handleStatusChange(entry.id, month)} className={`w-7 h-7 rounded text-white font-bold text-xs flex items-center justify-center mx-auto transition-all ${
                          entry.status[month] === MaintenanceStatus.Planned ? 'bg-indigo-500 hover:bg-indigo-600' : 
                          entry.status[month] === MaintenanceStatus.Realized ? 'bg-cyan-500 hover:bg-cyan-600' : 
                          'bg-gray-100 text-gray-400 hover:bg-gray-200'
                        }`}>
                        {entry.status[month] || ''}
                      </button>
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
            <tfoot className="bg-indigo-50 font-bold">
              <tr>
                <td colSpan={6} className="px-2 py-2 text-xs text-indigo-900 border-r">Programados</td>
                {monthlyTotals.map(({ month, planned }) => <td key={month} className="px-2 py-2 text-xs text-center border-r">{planned}</td>)}
              </tr>
              <tr>
                <td colSpan={6} className="px-2 py-2 text-xs text-indigo-900 border-r">Realizados</td>
                {monthlyTotals.map(({ month, realized }) => <td key={month} className="px-2 py-2 text-xs text-center border-r font-black text-cyan-600">{realized}</td>)}
              </tr>
              <tr>
                <td colSpan={6} className="px-2 py-2 text-xs text-indigo-900 border-r">Cumplimiento %</td>
                {monthlyTotals.map(({ month, compliance }) => <td key={month} className={`px-2 py-2 text-xs text-center border-r ${compliance >= 100 ? 'text-green-600' : 'text-orange-500'}`}>{compliance.toFixed(0)}%</td>)}
              </tr>
            </tfoot>
          </table>
        </div>
      </div>
      <div className="mt-6 flex flex-wrap items-center gap-3">
        <button onClick={() => setShowAddForm(!showAddForm)} className="px-4 py-2 bg-indigo-600 text-white font-semibold rounded shadow-sm hover:bg-indigo-700 transition-colors">
          {showAddForm ? 'Cancelar' : 'Anexar Tarea'}
        </button>
        <button onClick={handleExport} className="px-4 py-2 bg-white text-indigo-700 border border-indigo-200 font-semibold rounded shadow-sm hover:bg-indigo-50 transition-colors">
            Exportar PDF
        </button>
      </div>
       {showAddForm && (
          <form onSubmit={handleAddEntry} className="mt-4 p-4 border rounded-lg bg-gray-50 grid grid-cols-2 md:grid-cols-4 gap-4 animate-fadeIn">
            <select value={newEntry.inventoryId} onChange={e => setNewEntry({...newEntry, inventoryId: e.target.value})} className="p-2 border rounded col-span-2" required >
              <option value="">Seleccione equipo del inventario</option>
              {inventory.map(item => <option key={item.id} value={item.id}>{item.name} ({item.id})</option>)}
            </select>
            <input type="text" placeholder="Actividad" value={newEntry.actividad} onChange={e => setNewEntry({...newEntry, actividad: e.target.value})} className="p-2 border rounded" required />
            <button type="submit" className="px-4 py-2 bg-cyan-600 text-white font-semibold rounded shadow-sm hover:bg-cyan-700 transition-colors">Guardar Tarea</button>
          </form>
        )}
    </div>
  );
};

