interface HistoryPanelProps {
  inventory: InventoryItem[];
}

const HistoryPanel: React.FC<HistoryPanelProps> = ({ inventory }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRecord, setSelectedRecord] = useState<ExtendedMaintenanceRecord | null>(null);
  const printRef = useRef<HTMLDivElement>(null);

  const allRecords: ExtendedMaintenanceRecord[] = useMemo(() => {
    const records: ExtendedMaintenanceRecord[] = [];
    inventory.forEach(item => {
      item.lifecycle.maintenanceHistory.forEach(history => {
        records.push({
          ...history,
          equipmentName: item.name,
          equipmentId: item.id
        });
      });
    });
    return records.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [inventory]);

  const filteredRecords = useMemo(() => {
    return allRecords.filter(r => 
      r.equipmentName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.technician.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.description.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [allRecords, searchTerm]);

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 w-full animate-fadeIn">
      {selectedRecord && <RecordViewerModal record={selectedRecord} onClose={() => setSelectedRecord(null)} />}

      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <div>
            <h1 className="text-2xl font-bold text-indigo-900">Trazabilidad de Mantenimientos</h1>
            <p className="text-sm text-gray-500 uppercase tracking-widest font-bold">Historial Maestro de Calidad</p>
        </div>
        <div className="w-full md:w-64">
          <input
            type="text"
            placeholder="Filtrar registros..."
            className="w-full p-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="overflow-x-auto rounded-xl border border-gray-100">
        <table className="min-w-full divide-y divide-gray-100">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-widest">Fecha</th>
              <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-widest">Activo / Equipo</th>
              <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-widest">Técnico</th>
              <th className="px-6 py-4 text-center text-[10px] font-bold text-gray-400 uppercase tracking-widest">Acciones</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-50">
            {filteredRecords.length > 0 ? filteredRecords.map((record) => (
              <tr key={record.id} className="hover:bg-indigo-50/50 transition-colors">
                <td className="px-6 py-4 whitespace-nowrap text-sm font-bold text-gray-700">{record.date}</td>
                <td className="px-6 py-4">
                    <div className="text-sm font-black text-indigo-900">{record.equipmentName}</div>
                    <div className="text-[10px] text-gray-400 font-bold">{record.equipmentId} • {record.type}</div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{record.technician}</td>
                <td className="px-6 py-4 whitespace-nowrap text-center">
                  <button 
                    onClick={() => setSelectedRecord(record)}
                    className="p-2 text-indigo-600 hover:bg-indigo-100 rounded-lg transition-all"
                    title="Ver Registro Completo"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
