];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('schedule');

  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    try {
      const savedInventory = localStorage.getItem('inventory');
      return savedInventory ? JSON.parse(savedInventory) : initialInventory;
    } catch (error) {
      return initialInventory;
    }
  });

  const [schedule, setSchedule] = useState<ScheduleEntry[]>(() => {
    try {
      const savedSchedule = localStorage.getItem('maintenanceSchedule');
      return savedSchedule ? JSON.parse(savedSchedule) : initialSchedule;
    } catch (error) {
      return initialSchedule;
    }
  });

  useEffect(() => {
    localStorage.setItem('inventory', JSON.stringify(inventory));
  }, [inventory]);

  useEffect(() => {
    localStorage.setItem('maintenanceSchedule', JSON.stringify(schedule));
  }, [schedule]);

  const addMaintenanceToHistory = (itemId: string, historyEntry: MaintenanceRecordHistory) => {
    if (itemId === 'MANUAL-ENTRY') {
        const manualItem = inventory.find(i => i.id === 'MANUAL-LOGS');
        if (manualItem) {
            setInventory(prev => prev.map(i => i.id === 'MANUAL-LOGS' 
                ? { ...i, lifecycle: { ...i.lifecycle, maintenanceHistory: [...i.lifecycle.maintenanceHistory, historyEntry] } } 
                : i
            ));
        } else {
            const newManualItem: InventoryItem = {
                id: 'MANUAL-LOGS',
                name: 'Actividades Manuales',
                category: 'Log',
                model: 'N/A',
                serial: 'N/A',
                assignedTo: 'Sistema',
                purchaseDate: new Date().toISOString().split('T')[0],
                status: InventoryStatus.InUse,
                imageUrl: 'https://picsum.photos/seed/logs/400/300',
                lifecycle: { characteristics: 'Registros manuales fuera de inventario', maintenanceHistory: [historyEntry], usageHistory: '', observations: '' }
            };
            setInventory(prev => [...prev, newManualItem]);
        }
    } else {
        setInventory(prevInventory =>
          prevInventory.map(item =>
            item.id === itemId
              ? { ...item, lifecycle: { ...item.lifecycle, maintenanceHistory: [...item.lifecycle.maintenanceHistory, historyEntry] } }
              : item
          )
        );
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'record':
        return <MaintenanceRecord inventory={inventory} addMaintenanceToHistory={addMaintenanceToHistory} />;
      case 'schedule':
        return <MaintenanceSchedule schedule={schedule} setSchedule={setSchedule} inventory={inventory} />;
      case 'inventory':
        return <InventoryPanel inventory={inventory} setInventory={setInventory} />;
      case 'history':
        return <HistoryPanel inventory={inventory} />;
      default:
        return <MaintenanceSchedule schedule={schedule} setSchedule={setSchedule} inventory={inventory} />;
    }
  };

  const TabButton: React.FC<{tabName: Tab, label: string}> = ({tabName, label}) => {
    const isActive = activeTab === tabName;
    return (
        <button
            onClick={() => setActiveTab(tabName)}
            className={`px-4 py-3 text-sm font-black uppercase tracking-widest transition-all duration-300 focus:outline-none ${
                isActive 
                ? 'bg-indigo-900 text-white shadow-lg translate-y-[-2px]' 
                : 'bg-white text-indigo-900 hover:bg-indigo-50 border-b-2 border-indigo-100'
            }`}
        >
            {label}
        </button>
    );
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans">
      <header className="bg-white shadow-md border-b-4 border-indigo-900">
        <div className="container mx-auto px-6 py-4 flex flex-col md:flex-row justify-between items-center gap-4">
          <Logo className="h-14"/>
          <div className="text-center md:text-right">
            <h1 className="text-2xl font-black text-indigo-900 tracking-tighter uppercase">
              Gestor de Calidad Operativa
            </h1>
            <p className="text-xs font-bold text-[#00E5FF] uppercase tracking-[0.2em]">Asset Management System</p>
          </div>
        </div>
      </header>

      <main className="container mx-auto p-4 md:p-8">
        <div className="mb-8 overflow-hidden rounded-xl border border-indigo-100 shadow-sm">
            <nav className="flex flex-wrap md:flex-nowrap bg-white">
                <div className="flex-1 min-w-[150px]"><TabButton tabName="schedule" label="Programa Anual" /></div>
                <div className="flex-1 min-w-[150px]"><TabButton tabName="record" label="Nuevo Registro" /></div>
                <div className="flex-1 min-w-[150px]"><TabButton tabName="inventory" label="Inventario" /></div>
                <div className="flex-1 min-w-[150px]"><TabButton tabName="history" label="Historial Global" /></div>
            </nav>
        </div>

        <div className="animate-fadeIn">
          {renderContent()}
        </div>
      </main>

      <footer className="bg-indigo-900 text-white py-8 mt-12">
        <div className="container mx-auto px-6 text-center">
          <div className="flex justify-center mb-4 opacity-50 grayscale invert">
            <Logo className="h-10" />
          </div>
          <p className="text-sm font-bold tracking-widest uppercase">&copy; {new Date().getFullYear()} Vuelo Pharma Colombia</p>
          <p className="mt-2 text-xs text-indigo-300 uppercase tracking-widest">Comprometidos con la Calidad y la Excelencia Farmacéutica</p>
        </div>
      </footer>
    </div>
  );
};

