import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { ScheduleEntry, MaintenanceStatus, InventoryItem } from '../types';

declare const html2canvas: any;
declare global {
  interface Window {
    jspdf: any;
  }
}

const MONTHS = ['ENERO', 'FEBRERO', 'MARZO', 'ABRIL', 'MAYO', 'JUNIO', 'JULIO', 'AGOSTO', 'SEPTIEMBRE', 'OCTUBRE', 'NOVIEMBRE', 'DICIEMBRE'];
const YEAR_OPTIONS = ['2024', '2025', '2026', '2027', '2028', '2029', '2030'];

interface MaintenanceScheduleProps {
  schedule: ScheduleEntry[];
  setSchedule: React.Dispatch<React.SetStateAction<ScheduleEntry[]>>;
  inventory: InventoryItem[];
  selectedYear: string;
  setSelectedYear: (year: string) => void;
}

const MaintenanceSchedule: React.FC<MaintenanceScheduleProps> = ({ schedule, setSchedule, inventory, selectedYear, setSelectedYear }) => {

  const [newEntry, setNewEntry] = useState<{ inventoryId: string, actividad: string, respMantenimiento: string, frecuencia: string }>({ inventoryId: '', actividad: 'Revision Cyber Cloud', respMantenimiento: 'Mauricio Pino', frecuencia: '30-45 dias' });
  const [showAddForm, setShowAddForm] = useState(false);
  const printRef = useRef<HTMLDivElement>(null);

  const columnDefinitions = useMemo(() => [
    { id: 'equipo', label: 'Nombre de Equipo', minWidth: 150 },
    { id: 'modelo', label: 'Modelo/Serie', minWidth: 130 },
    { id: 'actividad', label: 'Actividad', minWidth: 150 },
    { id: 'respMantenimiento', label: 'Resp. Mantenimiento', minWidth: 130 },
    { id: 'respEquipo', label: 'Resp. equipo', minWidth: 130 },
    { id: 'frecuencia', label: 'Frecuencia', minWidth: 100 },
    ...MONTHS.map(month => ({ id: month, label: month, minWidth: 80 }))
  ], []);

  const [columnWidths, setColumnWidths] = useState<Record<string, number>>(() => {
    try {
        const savedWidths = localStorage.getItem('maintenanceScheduleColumnWidths');
        if (savedWidths) return JSON.parse(savedWidths);
    } catch (e) {}
    return columnDefinitions.reduce((acc, col) => {
        acc[col.id] = col.minWidth;
        return acc;
    }, {} as Record<string, number>);
  });

  useEffect(() => {
    localStorage.setItem('maintenanceScheduleColumnWidths', JSON.stringify(columnWidths));
  }, [columnWidths]);

  const resizingColumnRef = useRef<string | null>(null);
  const startXRef = useRef<number>(0);
  const startWidthRef = useRef<number>(0);

  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (resizingColumnRef.current) {
        const columnId = resizingColumnRef.current;
        const newWidth = startWidthRef.current + (e.clientX - startXRef.current);
        const columnDef = columnDefinitions.find(c => c.id === columnId);
        const minWidth = columnDef ? columnDef.minWidth : 50;

        if (newWidth >= minWidth) {
            setColumnWidths(prev => ({ ...prev, [columnId]: newWidth }));
        }
    }
  }, [columnDefinitions]);

  const handleMouseUp = useCallback(() => {
      resizingColumnRef.current = null;
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'default';
  }, [handleMouseMove]);

  const handleMouseDown = (e: React.MouseEvent, columnId: string) => {
      e.preventDefault();
      resizingColumnRef.current = columnId;
      startXRef.current = e.clientX;
      startWidthRef.current = columnWidths[columnId] || 0;
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
  };

  const handleStatusChange = (id: number, month: string) => {
    setSchedule(prevSchedule =>
      prevSchedule.map(entry => {
        if (entry.id === id) {
          const newStatus = { ...entry.status };
          const current = newStatus[month];
          if (current === MaintenanceStatus.Planned) {
            newStatus[month] = MaintenanceStatus.Realized;
          } else if (current === MaintenanceStatus.Realized) {
            delete newStatus[month];
          } else {
            newStatus[month] = MaintenanceStatus.Planned;
          }
          return { ...entry, status: newStatus };
        }
        return entry;
      })
    );
  };

  const handleEntryChange = (id: number, field: keyof ScheduleEntry, value: string) => {
    setSchedule(prevSchedule =>
      prevSchedule.map(entry => entry.id === id ? { ...entry, [field]: value } : entry)
    );
  };

  const handleAddEntry = (e: React.FormEvent) => {
    e.preventDefault();
    const selectedItem = inventory.find(i => i.id === newEntry.inventoryId);
    if (selectedItem && newEntry.actividad) {
      const newId = Math.max(...schedule.map(e => e.id), 0) + 1;
      const newScheduleEntry: ScheduleEntry = {
        id: newId,
        equipo: selectedItem.name,
        modelo: selectedItem.model,
        actividad: newEntry.actividad,
        respMantenimiento: newEntry.respMantenimiento,
        respEquipo: selectedItem.assignedTo,
        frecuencia: newEntry.frecuencia,
        status: {},
      };
      setSchedule([...schedule, newScheduleEntry]);
      setNewEntry({ inventoryId: '', actividad: 'Revision Cyber Cloud', respMantenimiento: 'Mauricio Pino', frecuencia: '30-45 dias' });
      setShowAddForm(false);
    } else {
      alert("Por favor, seleccione un equipo y complete la actividad.");
    }
  };

  const monthlyTotals = useMemo(() => {
    return MONTHS.map(month => {
      const planned = schedule.reduce((acc, entry) => acc + (Object.prototype.hasOwnProperty.call(entry.status, month) ? 1 : 0), 0);
      const realized = schedule.reduce((acc, entry) => acc + (entry.status[month] === MaintenanceStatus.Realized ? 1 : 0), 0);
      const compliance = planned > 0 ? (realized / planned) * 100 : 0;
      return { month, planned, realized, compliance };
    });
  }, [schedule]);

  const handleExport = async () => {
    const { jsPDF } = window.jspdf;
    const element = printRef.current;
    if (element) {
        const style = document.createElement('style');
        style.innerHTML = `
          table { font-size: 8px; border-collapse: collapse; }
          th, td { padding: 10px 4px !important; vertical-align: middle !important; }
          textarea { height: auto !important; min-height: 40px !important; overflow-y: hidden !important; border: none !important; resize: none !important; }
        `;
        element.appendChild(style);
        try {
            const canvas = await html2canvas(element, { scale: 3, useCORS: true });
            const data = canvas.toDataURL('image/png');
            const pdf = new jsPDF({ orientation: 'l', unit: 'mm', format: 'letter' });
            const margin = 10;
            const pdfWidth = pdf.internal.pageSize.getWidth();
            const imgWidth = pdfWidth - (margin * 2);
            const imgHeight = (canvas.height * imgWidth) / canvas.width;
            pdf.addImage(data, 'PNG', margin, margin, imgWidth, imgHeight);
            pdf.save(`programa-mantenimiento-vuelo-${selectedYear}.pdf`);
        } finally {
            element.removeChild(style);
        }
    }
  };

  const inputStyles = "bg-transparent w-full focus:outline-none focus:bg-gray-100 p-1 rounded transition-colors";

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 w-full animate-fadeIn">
      {/* Selector de Año y Encabezado */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 border-b border-indigo-50 pb-6">
        <div>
          <h1 className="text-2xl font-bold text-indigo-900">Programa Anual de Mantenimientos</h1>
          <p className="text-sm text-gray-500 font-medium">Cronograma preventivo de infraestructura y equipos</p>
        </div>

        <div className="flex items-center gap-4 bg-indigo-50/50 p-2 rounded-xl border border-indigo-100">
          <label className="text-xs font-black text-indigo-400 uppercase tracking-widest pl-2">Año del Programa:</label>
          <select 
            value={selectedYear} 
            onChange={(e) => setSelectedYear(e.target.value)}
            className="bg-white border-2 border-indigo-200 text-indigo-900 font-black rounded-lg px-4 py-2 focus:ring-2 focus:ring-indigo-500 outline-none cursor-pointer hover:border-indigo-400 transition-all shadow-sm"
          >
            {YEAR_OPTIONS.map(year => (
              <option key={year} value={year}>{year}</option>
            ))}
          </select>
        </div>
      </div>

      <div ref={printRef} className="overflow-visible">
        {/* Título dinámico para el PDF */}
        <div className="hidden print-only mb-6 text-center">
             <h2 className="text-xl font-bold text-indigo-900 uppercase">PROGRAMA ANUAL DE MANTENIMIENTO PREVENTIVO - AÑO {selectedYear}</h2>
        </div>

        <div className="overflow-x-auto rounded-xl border border-gray-100 shadow-sm">
          <table className="min-w-full divide-y divide-gray-200 border table-fixed">
            <colgroup>
                {columnDefinitions.map(col => <col key={col.id} style={{ width: `${columnWidths[col.id]}px` }} />)}
            </colgroup>
            <thead className="bg-gray-50">
              <tr>
                {columnDefinitions.map(col => (
                  <th 
                    key={col.id} 
                    className={`px-2 py-4 text-[10px] font-bold text-gray-400 uppercase tracking-wider border-r relative ${MONTHS.includes(col.id) ? 'text-center' : 'text-left'}`}
                  >
                    {col.label}
                    <div onMouseDown={e => handleMouseDown(e, col.id)} className="absolute top-0 right-[-1px] h-full w-2 cursor-col-resize z-10 hover:bg-indigo-300 transition-colors" />
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {schedule.length > 0 ? schedule.map(entry => (
                <tr key={entry.id} className="hover:bg-indigo-50/30 transition-colors">
                  <td className="px-1 py-1 whitespace-normal text-sm font-bold text-indigo-900 border-r align-top break-words">
                     <textarea value={entry.equipo} onChange={e => handleEntryChange(entry.id, 'equipo', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  <td className="px-1 py-1 whitespace-normal text-sm text-gray-500 border-r align-top break-words">
                     <textarea value={entry.modelo} onChange={e => handleEntryChange(entry.id, 'modelo', e.target.value)} className={`${inputStyles} resize-none font-medium`} rows={3}/>
                  </td>
                  <td className="px-1 py-1 whitespace-normal text-sm text-gray-600 border-r align-top break-words italic">
