                  <td className="px-2 py-2 whitespace-normal text-[11px] font-bold text-gray-500 border-r align-top break-words">
                    <textarea value={entry.respMantenimiento} onChange={e => handleEntryChange(entry.id, 'respMantenimiento', e.target.value)} className={`${inputStyles} resize-none uppercase`} rows={3}/>
                  </td>
                  <td className="px-1 py-1 whitespace-normal text-[11px] text-gray-500 border-r align-top break-words">
                      <textarea value={entry.respEquipo} onChange={e => handleEntryChange(entry.id, 'respEquipo', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  <td className="px-2 py-2 whitespace-nowrap text-[11px] text-gray-400 border-r align-top font-bold">
                     <textarea value={entry.frecuencia} onChange={e => handleEntryChange(entry.id, 'frecuencia', e.target.value)} className={`${inputStyles} resize-none`} rows={3}/>
                  </td>
                  {MONTHS.map(month => (
                    <td key={month} className="px-2 py-2 whitespace-nowrap text-sm text-gray-500 border-r text-center align-top">
                      <button onClick={() => handleStatusChange(entry.id, month)} className={`w-8 h-8 rounded-lg text-white font-black text-xs flex items-center justify-center mx-auto transition-all shadow-sm ${
