              <tr className="bg-[#00E5FF] text-indigo-900">
                <td colSpan={6} className="px-4 py-3 text-[10px] uppercase tracking-widest border-r">Cumplimiento %</td>
                {monthlyTotals.map(({ month, compliance }) => <td key={month} className={`px-2 py-3 text-xs text-center border-r border-cyan-400 font-black`}>{compliance.toFixed(0)}%</td>)}
              </tr>
            </tfoot>
          </table>
        </div>
      </div>

      <div className="mt-8 flex flex-wrap items-center justify-between gap-4">
