       {showAddForm && (
          <form onSubmit={handleAddEntry} className="mt-6 p-6 border-2 border-dashed border-indigo-200 rounded-2xl bg-indigo-50/30 grid grid-cols-1 md:grid-cols-12 gap-4 animate-slideDown">
            <div className="md:col-span-5">
                <label className="block text-[10px] font-black text-indigo-400 uppercase mb-2">Seleccione Activo del Inventario:</label>
                <select 
                    value={newEntry.inventoryId} 
                    onChange={e => setNewEntry({...newEntry, inventoryId: e.target.value})} 
                    className="w-full p-3 bg-white border border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none font-bold text-indigo-900" 
                    required 
                >
                    <option value="">Equipos registrados...</option>
                    {inventory.map(item => <option key={item.id} value={item.id}>{item.name} ({item.id})</option>)}
                </select>
            </div>
            <div className="md:col-span-4">
                <label className="block text-[10px] font-black text-indigo-400 uppercase mb-2">Actividad a Programar:</label>
                <input 
                    type="text" 
                    placeholder="Ej: Mantenimiento Preventivo Trimestral" 
                    value={newEntry.actividad} 
                    onChange={e => setNewEntry({...newEntry, actividad: e.target.value})} 
                    className="w-full p-3 border border-indigo-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" 
                    required 
                />
            </div>
            <div className="md:col-span-3 flex items-end">
                <button type="submit" className="w-full py-3 bg-[#00E5FF] text-white font-black rounded-xl shadow-md hover:bg-[#00c9e0] transition-all uppercase text-xs tracking-widest">
                    Guardar en {selectedYear}
                </button>
            </div>
          </form>
        )}

        <style>{`
            .print-only { display: none; }
            @media print {
                .print-only { display: block; }
                button, form, .no-print { display: none !important; }
                table { width: 100% !important; border: 1px solid #000 !important; }
            }
        `}</style>
    </div>
  );
};

export default MaintenanceSchedule;

import React, { useState, useMemo, useRef } from 'react';
import { InventoryItem, InventoryStatus, LifecycleData } from '../types';
import Logo from './Logo';

declare const html2canvas: any;
declare global {
  interface Window {
    jspdf: any;
  }
}

const statusColors: { [key in InventoryStatus]: string } = {
  [InventoryStatus.InUse]: 'bg-green-100 text-green-800',
  [InventoryStatus.InStorage]: 'bg-blue-100 text-blue-800',
  [InventoryStatus.UnderMaintenance]: 'bg-yellow-100 text-yellow-800',
  [InventoryStatus.Decommissioned]: 'bg-red-100 text-red-800',
};

const ItemFormModal: React.FC<{
  item: Omit<InventoryItem, 'id' | 'lifecycle'> | InventoryItem | null;
  onClose: () => void;
  onSave: (item: InventoryItem) => void;
}> = ({ item, onClose, onSave }) => {
  const [formData, setFormData] = useState<Omit<InventoryItem, 'id' | 'lifecycle'>>(() => {
    if (item && 'id' in item) {
      const { lifecycle, ...rest } = item;
      return { ...rest };
    }
    return {
      name: '', category: '', model: '', serial: '', assignedTo: '', 
      purchaseDate: new Date().toISOString().split('T')[0], 
      status: InventoryStatus.InStorage, imageUrl: ''
    };
  });

  React.useEffect(() => {
    if (item) {
        const { lifecycle, ...rest } = item as InventoryItem;
        setFormData({ ...rest });
    }
  }, [item]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setFormData(prev => ({ ...prev, imageUrl: event.target!.result as string }));
      };
      reader.readAsDataURL(e.target.files[0]);
    }
  };

  const handleSubmit = () => {
    const itemToSave = { 
      ...formData, 
      id: (item && 'id' in item) ? item.id : `EQ-${Date.now()}`, 
      lifecycle: (item && 'lifecycle' in item) ? item.lifecycle : { characteristics: '', maintenanceHistory: [], usageHistory: '', observations: ''} 
    };
    onSave(itemToSave as InventoryItem);
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50 p-4">
      <div className="bg-white p-6 rounded-xl shadow-xl w-full max-w-lg">
        <h3 className="text-xl font-bold mb-6 text-indigo-900">{item && 'id' in item ? 'Editar Equipo' : 'Añadir Nuevo Equipo'}</h3>
        <div className="grid grid-cols-2 gap-4 max-h-[70vh] overflow-y-auto pr-2">
          <div className="col-span-2 md:col-span-1">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Nombre</label>
            <input name="name" value={formData.name} onChange={handleChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Nombre" />
          </div>
          <div className="col-span-2 md:col-span-1">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Categoría</label>
            <input name="category" value={formData.category} onChange={handleChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Categoría" />
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Modelo</label>
            <input name="model" value={formData.model} onChange={handleChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Modelo" />
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Serial</label>
            <input name="serial" value={formData.serial} onChange={handleChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Serial" />
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Asignado a</label>
            <input name="assignedTo" value={formData.assignedTo} onChange={handleChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" placeholder="Responsable" />
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Fecha Compra</label>
            <input type="date" name="purchaseDate" value={formData.purchaseDate} onChange={handleChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div className="col-span-2">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Estado Operativo</label>
            <select name="status" value={formData.status} onChange={handleChange} className="w-full p-2 border rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none">
              {Object.values(InventoryStatus).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div className="col-span-2">
            <label className="block text-xs font-bold text-gray-400 uppercase mb-2">Foto del Equipo</label>
            <input type="file" accept="image/*" onChange={handleImageChange} className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-indigo-50 file:text-indigo-700 hover:file:bg-indigo-100 cursor-pointer"/>
            {formData.imageUrl && <img src={formData.imageUrl} alt="Preview" className="mt-4 h-24 w-24 object-cover rounded-xl shadow-sm border"/>}
          </div>
        </div>
        <div className="mt-8 flex justify-end space-x-3">
          <button className="px-4 py-2 bg-gray-100 text-gray-600 font-bold rounded-lg hover:bg-gray-200 transition-colors" onClick={onClose}>Cancelar</button>
          <button className="px-6 py-2 bg-indigo-600 text-white font-bold rounded-lg hover:bg-indigo-700 transition-colors shadow-lg" onClick={handleSubmit}>Guardar Cambios</button>
        </div>
      </div>
    </div>
  );
};

const LifecycleSheetModal: React.FC<{
    item: InventoryItem;
    onClose: () => void;
    onSave: (itemId: string, data: LifecycleData) => void;
}> = ({ item, onClose, onSave }) => {
    const sheetRef = useRef<HTMLDivElement>(null);
    const [isEditing, setIsEditing] = useState(false);
    const [editableData, setEditableData] = useState<LifecycleData>(JSON.parse(JSON.stringify(item.lifecycle)));

    const handleFieldChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        setEditableData({ ...editableData, [e.target.name]: e.target.value });
    };

    const handleSaveChanges = () => {
        onSave(item.id, editableData);
        setIsEditing(false);
    };

    const handleExport = async () => {
        const { jsPDF } = window.jspdf;
        const element = sheetRef.current;
        if (element) {
            const wasEditing = isEditing;
            if(wasEditing) setIsEditing(false);

            await new Promise(resolve => setTimeout(resolve, 100));

            const canvas = await html2canvas(element, { scale: 2, useCORS: true });
            const data = canvas.toDataURL('image/png');

            const pdf = new jsPDF('p', 'mm', 'a4');
            const pdfWidth = pdf.internal.pageSize.getWidth();
            const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

            pdf.addImage(data, 'PNG', 0, 0, pdfWidth, pdfHeight);
            pdf.save(`hoja-de-vida-${item.id}.pdf`);

            if(wasEditing) setIsEditing(true);
        }
    };

    const renderField = (label: string, name: keyof LifecycleData, value: string, rows = 3) => (
         <div className="mb-4">
            <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-widest mb-1">{label}</h4>
            {isEditing ? (
                <textarea name={name} value={value} onChange={handleFieldChange} rows={rows} className="w-full p-2 border border-indigo-100 rounded-lg text-sm bg-indigo-50/30 focus:ring-2 focus:ring-indigo-500 outline-none" />
            ) : (
                <p className="text-sm text-gray-700 bg-gray-50 p-3 rounded-lg border border-gray-100 whitespace-pre-wrap min-h-[4rem]">{value || 'No especificado'}</p>
            )}
        </div>
    );

    const InfoPill: React.FC<{label: string, value: string}> = ({label, value}) => (
      <div className="bg-white border border-gray-100 p-3 rounded-xl shadow-sm">
        <p className="text-[10px] font-black text-gray-400 uppercase tracking-tighter">{label}</p>
        <p className="text-sm font-bold text-indigo-900">{value}</p>
      </div>
    );

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex justify-center items-center z-50 p-4">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl max-h-[95vh] flex flex-col overflow-hidden">
                <div className="flex justify-between items-center p-4 border-b bg-gray-50 no-print">
                   <div className="flex space-x-2">
                        {isEditing ? (
                             <button onClick={handleSaveChanges} className="px-4 py-2 bg-green-600 text-white text-xs font-black rounded-lg uppercase tracking-widest">Guardar Cambios</button>
                        ) : (
                             <button onClick={() => setIsEditing(true)} className="px-4 py-2 bg-indigo-600 text-white text-xs font-black rounded-lg uppercase tracking-widest">Editar Hoja de Vida</button>
                        )}
                        <button onClick={handleExport} className="px-4 py-2 bg-white border border-gray-300 text-gray-600 text-xs font-black rounded-lg uppercase tracking-widest">Descargar PDF</button>
                   </div>
                   <button onClick={onClose} className="p-2 text-gray-400 hover:text-gray-600 transition-colors">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                   </button>
                </div>

                <div className="flex-grow overflow-y-auto bg-gray-100 p-4 md:p-8">
                    <div ref={sheetRef} className="bg-white p-10 shadow-sm max-w-3xl mx-auto border border-gray-200">
                        <div className="flex justify-between items-center mb-8 border-b-2 border-indigo-900 pb-4">
                            <Logo className="h-16" />
                            <div className="text-right">
                                <h2 className="text-xl font-black text-indigo-900 uppercase">Hoja de Vida de Activo</h2>
                                <p className="text-xs font-bold text-gray-400">ID: {item.id}</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
                            <InfoPill label="Nombre" value={item.name} />
                            <InfoPill label="Modelo" value={item.model} />
                            <InfoPill label="Categoría" value={item.category} />
                            <InfoPill label="Asignado" value={item.assignedTo} />
                        </div>

                        <div className="flex flex-col md:flex-row gap-8 mb-8">
                            <div className="flex-1">
                                {renderField('Características Técnicas', 'characteristics', editableData.characteristics)}
                                {renderField('Uso y Aplicación', 'usageHistory', editableData.usageHistory)}
                                {renderField('Observaciones de Calidad', 'observations', editableData.observations)}
                            </div>
                            {item.imageUrl && (
                                <div className="w-full md:w-64">
                                    <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-widest mb-2">Registro Visual</h4>
                                    <div className="border p-2 rounded-xl bg-gray-50 shadow-inner">
                                        <img src={item.imageUrl} alt={item.name} className="w-full h-auto rounded-lg" />
                                    </div>
                                </div>
                            )}
                        </div>

                        <div className="mt-8">
                            <h4 className="text-xs font-bold text-indigo-900 uppercase border-b border-indigo-100 pb-2 mb-4">Resumen de Mantenimientos</h4>
                            <div className="space-y-3">
                                {item.lifecycle.maintenanceHistory.length > 0 ? item.lifecycle.maintenanceHistory.map((m, i) => (
                                    <div key={i} className="flex justify-between items-center text-xs p-3 bg-gray-50 rounded-lg border border-gray-100">
                                        <div>
                                            <span className="font-bold text-indigo-900">{m.date}</span>
                                            <span className="mx-2 text-gray-300">|</span>
                                            <span className="uppercase font-medium">{m.type}</span>
                                        </div>
                                        <span className="italic text-gray-500">{m.technician}</span>
                                    </div>
                                )) : (
                                    <p className="text-sm italic text-gray-400 text-center py-4">Sin registros de mantenimiento previos.</p>
                                )}
                            </div>
                        </div>

                        <div className="mt-16 pt-8 border-t border-gray-100 grid grid-cols-2 gap-8 text-center">
                            <div>
                                <div className="h-10"></div>
                                <div className="border-t border-gray-300 pt-1">
                                    <p className="text-[10px] font-bold text-gray-400 uppercase">Firma Responsable</p>
                                </div>
                            </div>
                            <div>
                                <div className="h-10"></div>
                                <div className="border-t border-gray-300 pt-1">
                                    <p className="text-[10px] font-bold text-gray-400 uppercase">Revisión de Calidad</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const InventoryPanel: React.FC<{
  inventory: InventoryItem[];
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
}> = ({ inventory, setInventory }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingItem, setEditingItem] = useState<InventoryItem | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [selectedLifecycleItem, setSelectedLifecycleItem] = useState<InventoryItem | null>(null);

  const filteredInventory = useMemo(() => 
    inventory.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.assignedTo.toLowerCase().includes(searchTerm.toLowerCase())
    ), [inventory, searchTerm]);

  const handleSave = (item: InventoryItem) => {
    if (editingItem) {
      setInventory(prev => prev.map(i => i.id === item.id ? item : i));
    } else {
      setInventory(prev => [...prev, item]);
    }
    setEditingItem(null);
    setIsAdding(false);
  };

  const handleDelete = (id: string) => {
    if(confirm('¿Está seguro de eliminar este equipo del inventario?')) {
        setInventory(prev => prev.filter(i => i.id !== id));
    }
  };

  const handleUpdateLifecycle = (itemId: string, data: LifecycleData) => {
      setInventory(prev => prev.map(i => i.id === itemId ? { ...i, lifecycle: data } : i));
      setSelectedLifecycleItem(null);
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 w-full animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
