            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <button 
            onClick={() => setIsAdding(true)} 
            className="bg-indigo-600 text-white px-6 py-2.5 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg hover:scale-105 active:scale-95 uppercase text-xs tracking-widest"
          >
            Nuevo Activo
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {filteredInventory.map(item => (
          <div key={item.id} className="bg-white rounded-2xl border border-gray-100 overflow-hidden shadow-sm hover:shadow-xl transition-all group">
            <div className="relative h-40 overflow-hidden bg-gray-100">
              <img src={item.imageUrl || 'https://via.placeholder.com/400x300?text=Sin+Imagen'} alt={item.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
              <div className={`absolute top-3 right-3 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest shadow-md ${statusColors[item.status]}`}>
                {item.status}
              </div>
            </div>
            <div className="p-5">
              <div className="flex justify-between items-start mb-2">
                <div>
                    <h3 className="font-bold text-indigo-900 leading-tight">{item.name}</h3>
                    <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{item.id}</p>
                </div>
              </div>
              <div className="space-y-1.5 mb-4">
                <p className="text-xs text-gray-600 flex items-center gap-2">
                    <span className="font-bold text-indigo-400">MODELO:</span> {item.model}
                </p>
                <p className="text-xs text-gray-600 flex items-center gap-2">
                    <span className="font-bold text-indigo-400">RESP:</span> {item.assignedTo}
                </p>
              </div>
              <div className="grid grid-cols-3 gap-2">
