    if (item) {
      const { lifecycle, ...rest } = item;
      return { ...rest };
    }
    return {
      id: `EQ-${Date.now()}`,
      name: '',
      category: '',
      model: '',
      serial: '',
      assignedTo: '', 
      purchaseDate: new Date().toISOString().split('T')[0], 
      status: InventoryStatus.InStorage,
