            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Modelo</label>
            <input name="model" value={formData.model} onChange={handleChange} className="w-full p-2.5 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all" placeholder="Modelo" />
