};

const LifecycleSheetModal: React.FC<{
    item: InventoryItem;
    onClose: () => void;
    onSave: (itemId: string, data: LifecycleData) => void;
}> = ({ item, onClose, onSave }) => {
    const sheetRef = useRef<HTMLDivElement>(null);
    const [isEditing, setIsEditing] = useState(false);
    const [editableData, setEditableData] = useState<LifecycleData>(JSON.parse(JSON.stringify(item.lifecycle)));

    const handleFieldChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        setEditableData({ ...editableData, [e.target.name]: e.target.value });
    };

    const handleSaveChanges = () => {
        onSave(item.id, editableData);
        setIsEditing(false);
    };

    const handleExport = async () => {
        const { jsPDF } = window.jspdf;
        const element = sheetRef.current;
        if (element) {
            const wasEditing = isEditing;
            if(wasEditing) setIsEditing(false);

            await new Promise(resolve => setTimeout(resolve, 150));

            const canvas = await html2canvas(element, { scale: 2, useCORS: true, logging: false });
            const data = canvas.toDataURL('image/png');

            const pdf = new jsPDF('p', 'mm', 'a4');
            const pdfWidth = pdf.internal.pageSize.getWidth();
            const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

            pdf.addImage(data, 'PNG', 0, 0, pdfWidth, pdfHeight);
            pdf.save(`hoja-de-vida-${item.id}.pdf`);

            if(wasEditing) setIsEditing(true);
        }
    };

    const renderField = (label: string, name: keyof LifecycleData, value: string, rows = 3) => (
         <div className="mb-6">
            <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2 flex items-center gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-indigo-400"></span>
                {label}
            </h4>
            {isEditing ? (
                <textarea name={name} value={value} onChange={handleFieldChange} rows={rows} className="w-full p-3 border border-indigo-100 rounded-xl text-sm bg-indigo-50/20 focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
            ) : (
                <p className="text-sm text-gray-700 bg-gray-50/50 p-4 rounded-xl border border-gray-100 whitespace-pre-wrap min-h-[5rem] leading-relaxed">
                    {value || 'Sin información registrada en este campo.'}
                </p>
            )}
        </div>
    );

    const InfoPill: React.FC<{label: string, value: string}> = ({label, value}) => (
      <div className="bg-white border border-gray-100 p-4 rounded-2xl shadow-sm hover:border-indigo-100 transition-colors">
        <p className="text-[9px] font-black text-gray-400 uppercase tracking-tighter mb-1">{label}</p>
        <p className="text-sm font-bold text-indigo-900 truncate">{value || 'N/A'}</p>
      </div>
    );

    return (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md flex justify-center items-center z-[60] p-4">
            <div className="bg-white rounded-3xl shadow-2xl w-full max-w-5xl max-h-[95vh] flex flex-col overflow-hidden animate-slideUp">
                <div className="flex justify-between items-center p-5 border-b bg-white no-print">
                   <div className="flex items-center gap-4">
                        <span className="text-xs font-black text-indigo-900 uppercase tracking-widest bg-indigo-50 px-3 py-1.5 rounded-lg">Ficha Técnica Oficial</span>
                        <div className="flex gap-2">
                            {isEditing ? (
                                 <button onClick={handleSaveChanges} className="px-4 py-2 bg-green-600 text-white text-[10px] font-black rounded-xl uppercase tracking-widest hover:bg-green-700 shadow-lg shadow-green-100">Guardar</button>
                            ) : (
                                 <button onClick={() => setIsEditing(true)} className="px-4 py-2 bg-indigo-900 text-white text-[10px] font-black rounded-xl uppercase tracking-widest hover:bg-indigo-800 shadow-lg shadow-indigo-100">Editar</button>
                            )}
                            <button onClick={handleExport} className="px-4 py-2 bg-white border border-gray-200 text-gray-600 text-[10px] font-black rounded-xl uppercase tracking-widest hover:bg-gray-50">PDF</button>
                        </div>
                   </div>
                   <button onClick={onClose} className="p-2 bg-gray-50 rounded-full text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 transition-all">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                   </button>
                </div>

                <div className="flex-grow overflow-y-auto bg-gray-50/50 p-4 md:p-8 custom-scrollbar">
                    <div ref={sheetRef} className="bg-white p-10 shadow-sm max-w-4xl mx-auto border border-gray-200 rounded-lg">
                        <div className="flex justify-between items-center mb-10 border-b-4 border-indigo-900 pb-6">
                            <Logo className="h-16" />
                            <div className="text-right">
                                <h2 className="text-2xl font-black text-indigo-900 uppercase leading-none mb-1">Hoja de Vida de Activo</h2>
                                <p className="text-xs font-bold text-[#00E5FF] uppercase tracking-[0.3em]">Calidad Vuelo Pharma</p>
