                            </h4>
                            <div className="space-y-4">
                                {item.lifecycle.maintenanceHistory.length > 0 ? item.lifecycle.maintenanceHistory.map((m, i) => (
                                    <div key={i} className="flex flex-col md:flex-row md:items-center justify-between gap-2 p-4 bg-gray-50 hover:bg-indigo-50/30 rounded-2xl border border-gray-100 transition-colors">
