            <input
              type="text"
              placeholder="Filtrar por nombre, categoría, ID o responsable..."
              className="w-full pl-12 pr-6 py-3.5 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm group-hover:bg-white"
              value={searchTerm}
