          </div>
          <button 
            onClick={() => setIsAdding(true)} 
            className="bg-indigo-900 text-white px-8 py-3.5 rounded-2xl font-black hover:bg-indigo-800 transition-all shadow-xl shadow-indigo-100 hover:-translate-y-1 active:scale-95 text-xs uppercase tracking-widest whitespace-nowrap"
          >
            Agregar Activo
          </button>
        </div>
      </div>

