const LifecycleSheetModal: React.FC<{
    item: InventoryItem;
    onClose: () => void;
    onSave: (itemId: string, data: LifecycleData) => void;
}> = ({ item, onClose, onSave }) => {
    const sheetRef = useRef<HTMLDivElement>(null);
    const [isEditing, setIsEditing] = useState(false);
    const [editableData, setEditableData] = useState<LifecycleData>(JSON.parse(JSON.stringify(item.lifecycle)));

    const handleFieldChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        setEditableData({ ...editableData, [e.target.name]: e.target.value });
    };

    const handleSaveChanges = () => {
        onSave(item.id, editableData);
        setIsEditing(false);
    };

    const handleExport = async () => {
        const { jsPDF } = window.jspdf;
        const element = sheetRef.current;
        if (element) {
            const wasEditing = isEditing;
            if(wasEditing) setIsEditing(false);
            await new Promise(resolve => setTimeout(resolve, 150));
            const canvas = await html2canvas(element, { scale: 2, useCORS: true });
            const data = canvas.toDataURL('image/png');
            const pdf = new jsPDF('p', 'mm', 'a4');
            const pdfWidth = pdf.internal.pageSize.getWidth();
            const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
            pdf.addImage(data, 'PNG', 0, 0, pdfWidth, pdfHeight);
            pdf.save(`hoja-de-vida-${item.id}.pdf`);
            if(wasEditing) setIsEditing(true);
        }
    };

    const renderField = (label: string, name: keyof LifecycleData, value: string) => (
         <div className="mb-6">
            <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">{label}</h4>
            {isEditing ? (
                <textarea name={name} value={value} onChange={handleFieldChange} rows={4} className="w-full p-3 border border-indigo-100 rounded-xl text-sm bg-indigo-50/20 focus:ring-2 focus:ring-indigo-500 outline-none" />
            ) : (
                <p className="text-sm text-gray-700 bg-gray-50/50 p-4 rounded-xl border border-gray-100 whitespace-pre-wrap min-h-[5rem] leading-relaxed">
                    {value || 'Sin información registrada.'}
                </p>
            )}
        </div>
    );

    return (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md flex justify-center items-center z-[60] p-4">
            <div className="bg-white rounded-3xl shadow-2xl w-full max-w-5xl max-h-[95vh] flex flex-col overflow-hidden">
                <div className="flex justify-between items-center p-5 border-b bg-white no-print">
                   <div className="flex gap-3">
                        {isEditing ? (
                             <button onClick={handleSaveChanges} className="px-5 py-2 bg-green-600 text-white text-[10px] font-black rounded-xl uppercase tracking-widest">Guardar Cambios</button>
                        ) : (
                             <button onClick={() => setIsEditing(true)} className="px-5 py-2 bg-indigo-900 text-white text-[10px] font-black rounded-xl uppercase tracking-widest">Editar Ficha</button>
                        )}
                        <button onClick={handleExport} className="px-5 py-2 bg-white border border-gray-200 text-gray-600 text-[10px] font-black rounded-xl uppercase tracking-widest hover:bg-gray-50">Descargar PDF</button>
                   </div>
                   <button onClick={onClose} className="p-2 bg-gray-100 rounded-full text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 transition-all">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                   </button>
                </div>

                <div className="flex-grow overflow-y-auto bg-gray-50/30 p-4 md:p-8 custom-scrollbar">
                    <div ref={sheetRef} className="bg-white p-10 shadow-sm max-w-4xl mx-auto border border-gray-200 rounded-xl">
                        <div className="flex justify-between items-center mb-10 border-b-4 border-indigo-900 pb-6">
                            <Logo className="h-16" />
                            <div className="text-right">
                                <h2 className="text-2xl font-black text-indigo-900 uppercase leading-none mb-1">Hoja de Vida de Activo</h2>
                                <p className="text-xs font-bold text-[#00E5FF] uppercase tracking-[0.2em]">Asset Quality Management</p>
                                <p className="text-xs font-black text-gray-300 mt-2">REGISTRO: {item.id}</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
                            <div className="bg-white border p-4 rounded-2xl shadow-sm"><p className="text-[9px] font-black text-gray-400 uppercase mb-1">Equipo</p><p className="text-sm font-bold text-indigo-900">{item.name}</p></div>
                            <div className="bg-white border p-4 rounded-2xl shadow-sm"><p className="text-[9px] font-black text-gray-400 uppercase mb-1">Modelo</p><p className="text-sm font-bold text-indigo-900">{item.model || 'N/A'}</p></div>
                            <div className="bg-white border p-4 rounded-2xl shadow-sm"><p className="text-[9px] font-black text-gray-400 uppercase mb-1">Categoría</p><p className="text-sm font-bold text-indigo-900">{item.category}</p></div>
                            <div className="bg-white border p-4 rounded-2xl shadow-sm"><p className="text-[9px] font-black text-gray-400 uppercase mb-1">Asignado</p><p className="text-sm font-bold text-indigo-900">{item.assignedTo}</p></div>
                        </div>

                        <div className="flex flex-col md:flex-row gap-10">
                            <div className="flex-1">
                                {renderField('Características Técnicas', 'characteristics', editableData.characteristics)}
                                {renderField('Uso y Aplicación en Planta', 'usageHistory', editableData.usageHistory)}
                                {renderField('Observaciones Adicionales', 'observations', editableData.observations)}
                            </div>
                            {item.imageUrl && (
                                <div className="w-full md:w-64">
                                    <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-3">Registro Fotográfico</h4>
                                    <img src={item.imageUrl} alt={item.name} className="w-full aspect-square object-cover rounded-3xl shadow-xl border-4 border-white" />
                                </div>
                            )}
                        </div>

                        <div className="mt-10 pt-10 border-t border-gray-100">
                            <h4 className="text-[10px] font-black text-indigo-900 uppercase mb-6 flex items-center justify-between">
                                <span>Trazabilidad de Intervenciones</span>
                                <span className="bg-indigo-900 text-white px-2 py-0.5 rounded text-[8px]">{item.lifecycle.maintenanceHistory.length} REGISTROS</span>
                            </h4>
                            <div className="space-y-3">
                                {item.lifecycle.maintenanceHistory.map((m, i) => (
                                    <div key={i} className="flex justify-between items-center p-4 bg-gray-50 rounded-2xl border border-gray-100">
                                        <div><span className="text-xs font-black text-indigo-900 uppercase">{m.type}</span><span className="ml-3 text-[10px] text-gray-400 font-bold">{m.date}</span></div>
                                        <div className="text-right font-bold text-xs text-indigo-700">{m.technician}</div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const InventoryPanel: React.FC<{
  inventory: InventoryItem[];
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
}> = ({ inventory, setInventory }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingItem, setEditingItem] = useState<InventoryItem | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [selectedLifecycleItem, setSelectedLifecycleItem] = useState<InventoryItem | null>(null);

  const filteredInventory = useMemo(() => 
    inventory.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.assignedTo.toLowerCase().includes(searchTerm.toLowerCase())
    ), [inventory, searchTerm]);

  const handleSave = (item: InventoryItem) => {
    if (editingItem) {
      setInventory(prev => prev.map(i => i.id === item.id ? item : i));
      setEditingItem(null);
    } else {
      setInventory(prev => [...prev, item]);
      setIsAdding(false);
    }
  };

  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 w-full animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
