            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <button 
            onClick={() => setIsAdding(true)} 
            className="bg-indigo-900 text-white px-8 py-3.5 rounded-2xl font-black hover:bg-indigo-800 transition-all shadow-xl shadow-indigo-100 text-xs uppercase tracking-widest"
          >
            Nuevo Activo
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
        {filteredInventory.map(item => (
          <div key={item.id} className="bg-white rounded-3xl border border-gray-50 overflow-hidden shadow-sm hover:shadow-2xl transition-all group flex flex-col h-full">
            <div className="relative h-48 overflow-hidden bg-gray-50">
              <img src={item.imageUrl || 'https://via.placeholder.com/600x400?text=SIN+IMAGEN'} alt={item.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
              <div className={`absolute top-4 right-4 px-3 py-1 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-md ${statusColors[item.status]}`}>
                {item.status}
              </div>
            </div>
            <div className="p-6 flex-grow flex flex-col">
              <h3 className="text-lg font-black text-indigo-900 leading-tight mb-4 flex-grow line-clamp-2">{item.name}</h3>
              <div className="space-y-1 mb-6">
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">ID: {item.id}</p>
                <p className="text-xs text-indigo-600 font-bold">RESP: {item.assignedTo}</p>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => setEditingItem(item)} className="p-3 bg-gray-50 text-gray-400 rounded-2xl hover:bg-indigo-900 hover:text-white transition-all text-xs font-black uppercase">Editar</button>
                <button onClick={() => setSelectedLifecycleItem(item)} className="p-3 bg-indigo-50 text-indigo-600 rounded-2xl hover:bg-indigo-600 hover:text-white transition-all text-xs font-black uppercase">Ficha</button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {(isAdding || editingItem) && (
        <ItemFormModal
          item={editingItem}
          onClose={() => { setEditingItem(null); setIsAdding(false); }}
          onSave={handleSave}
        />
      )}

      {selectedLifecycleItem && (
          <LifecycleSheetModal 
            item={selectedLifecycleItem} 
            onClose={() => setSelectedLifecycleItem(null)}
            onSave={(itemId, data) => {
              setInventory(prev => prev.map(i => i.id === itemId ? { ...i, lifecycle: data } : i));
              setSelectedLifecycleItem(null);
            }}
          />
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

