            <input name="id" value={formData.id} onChange={handleChange} className="w-full p-2.5 bg-gray-50 border border-gray-100 rounded-xl outline-none" disabled={!!item} />
          </div>
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Modelo</label>
            <input name="model" value={formData.model} onChange={handleChange} className="w-full p-2.5 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Serial / Placa</label>
            <input name="serial" value={formData.serial} onChange={handleChange} className="w-full p-2.5 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Asignado a</label>
            <input name="assignedTo" value={formData.assignedTo} onChange={handleChange} className="w-full p-2.5 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Fecha de Compra</label>
            <input type="date" name="purchaseDate" value={formData.purchaseDate} onChange={handleChange} className="w-full p-2.5 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none" />
          </div>
          <div className="col-span-2">
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-1">Estado Operativo Actual</label>
            <select name="status" value={formData.status} onChange={handleChange} className="w-full p-2.5 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none cursor-pointer">
              {Object.values(InventoryStatus).map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
          <div className="col-span-2 mt-4">
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2">Foto / Evidencia Visual</label>
            <div className="flex items-center gap-4">
                <input type="file" accept="image/*" onChange={handleImageChange} className="text-xs text-gray-500" />
                {formData.imageUrl && <img src={formData.imageUrl} alt="Preview" className="h-16 w-16 object-cover rounded-xl shadow-sm border"/>}
            </div>
          </div>
        </div>
        <div className="mt-8 flex justify-end space-x-3">
          <button className="px-6 py-2.5 bg-gray-100 text-gray-500 text-xs font-black uppercase rounded-xl hover:bg-gray-200 transition-colors" onClick={onClose}>Cancelar</button>
          <button className="px-8 py-2.5 bg-indigo-900 text-white text-xs font-black uppercase rounded-xl hover:bg-indigo-800 transition-all shadow-lg" onClick={handleSubmit}>Guardar Activo</button>
        </div>
      </div>
    </div>
  );
};

const LifecycleSheetModal: React.FC<{
    item: InventoryItem;
    onClose: () => void;
    onSave: (itemId: string, data: LifecycleData) => void;
}> = ({ item, onClose, onSave }) => {
    const sheetRef = useRef<HTMLDivElement>(null);
    const [isEditing, setIsEditing] = useState(false);
    const [editableData, setEditableData] = useState<LifecycleData>(JSON.parse(JSON.stringify(item.lifecycle)));

    const handleFieldChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        setEditableData({ ...editableData, [e.target.name]: e.target.value });
    };

    const handleSaveChanges = () => {
        onSave(item.id, editableData);
        setIsEditing(false);
    };

    const handleExport = async () => {
        const { jsPDF } = window.jspdf;
        const element = sheetRef.current;
        if (element) {
            const wasEditing = isEditing;
            if(wasEditing) setIsEditing(false);
            await new Promise(resolve => setTimeout(resolve, 150));
            const canvas = await html2canvas(element, { scale: 2, useCORS: true });
            const data = canvas.toDataURL('image/png');
            const pdf = new jsPDF('p', 'mm', 'a4');
            const pdfWidth = pdf.internal.pageSize.getWidth();
            const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
            pdf.addImage(data, 'PNG', 0, 0, pdfWidth, pdfHeight);
            pdf.save(`hoja-de-vida-${item.id}.pdf`);
            if(wasEditing) setIsEditing(true);
        }
    };

    const renderField = (label: string, name: keyof LifecycleData, value: string) => (
         <div className="mb-6">
            <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-2">{label}</h4>
            {isEditing ? (
                <textarea name={name} value={value} onChange={handleFieldChange} rows={4} className="w-full p-3 border border-indigo-100 rounded-xl text-sm bg-indigo-50/20 focus:ring-2 focus:ring-indigo-500 outline-none" />
            ) : (
                <p className="text-sm text-gray-700 bg-gray-50/50 p-4 rounded-xl border border-gray-100 whitespace-pre-wrap min-h-[5rem] leading-relaxed">
                    {value || 'Sin información registrada.'}
                </p>
            )}
        </div>
    );

    return (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md flex justify-center items-center z-[60] p-4">
            <div className="bg-white rounded-3xl shadow-2xl w-full max-w-5xl max-h-[95vh] flex flex-col overflow-hidden">
                <div className="flex justify-between items-center p-5 border-b bg-white no-print">
                   <div className="flex gap-3">
                        {isEditing ? (
                             <button onClick={handleSaveChanges} className="px-5 py-2 bg-green-600 text-white text-[10px] font-black rounded-xl uppercase tracking-widest">Guardar Cambios</button>
                        ) : (
                             <button onClick={() => setIsEditing(true)} className="px-5 py-2 bg-indigo-900 text-white text-[10px] font-black rounded-xl uppercase tracking-widest">Editar Ficha</button>
                        )}
                        <button onClick={handleExport} className="px-5 py-2 bg-white border border-gray-200 text-gray-600 text-[10px] font-black rounded-xl uppercase tracking-widest hover:bg-gray-50">Descargar PDF</button>
                   </div>
                   <button onClick={onClose} className="p-2 bg-gray-100 rounded-full text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 transition-all">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                   </button>
                </div>

                <div className="flex-grow overflow-y-auto bg-gray-50/30 p-4 md:p-8 custom-scrollbar">
                    <div ref={sheetRef} className="bg-white p-10 shadow-sm max-w-4xl mx-auto border border-gray-200 rounded-xl">
                        <div className="flex justify-between items-center mb-10 border-b-4 border-indigo-900 pb-6">
                            <Logo className="h-16" />
                            <div className="text-right">
                                <h2 className="text-2xl font-black text-indigo-900 uppercase leading-none mb-1">Hoja de Vida de Activo</h2>
                                <p className="text-xs font-bold text-[#00E5FF] uppercase tracking-[0.2em]">Asset Quality Management</p>
                                <p className="text-xs font-black text-gray-300 mt-2">REGISTRO: {item.id}</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
                            <div className="bg-white border p-4 rounded-2xl shadow-sm"><p className="text-[9px] font-black text-gray-400 uppercase mb-1">Equipo</p><p className="text-sm font-bold text-indigo-900">{item.name}</p></div>
                            <div className="bg-white border p-4 rounded-2xl shadow-sm"><p className="text-[9px] font-black text-gray-400 uppercase mb-1">Modelo</p><p className="text-sm font-bold text-indigo-900">{item.model || 'N/A'}</p></div>
                            <div className="bg-white border p-4 rounded-2xl shadow-sm"><p className="text-[9px] font-black text-gray-400 uppercase mb-1">Categoría</p><p className="text-sm font-bold text-indigo-900">{item.category}</p></div>
                            <div className="bg-white border p-4 rounded-2xl shadow-sm"><p className="text-[9px] font-black text-gray-400 uppercase mb-1">Asignado</p><p className="text-sm font-bold text-indigo-900">{item.assignedTo}</p></div>
                        </div>

                        <div className="flex flex-col md:flex-row gap-10">
                            <div className="flex-1">
                                {renderField('Características Técnicas', 'characteristics', editableData.characteristics)}
                                {renderField('Uso y Aplicación en Planta', 'usageHistory', editableData.usageHistory)}
                                {renderField('Observaciones Adicionales', 'observations', editableData.observations)}
                            </div>
                            {item.imageUrl && (
                                <div className="w-full md:w-64">
                                    <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mb-3">Registro Fotográfico</h4>
                                    <img src={item.imageUrl} alt={item.name} className="w-full aspect-square object-cover rounded-3xl shadow-xl border-4 border-white" />
                                </div>
                            )}
                        </div>

                        <div className="mt-10 pt-10 border-t border-gray-100">
                            <h4 className="text-[10px] font-black text-indigo-900 uppercase mb-6 flex items-center justify-between">
                                <span>Trazabilidad de Intervenciones</span>
                                <span className="bg-indigo-900 text-white px-2 py-0.5 rounded text-[8px]">{item.lifecycle.maintenanceHistory.length} REGISTROS</span>
                            </h4>
                            <div className="space-y-3">
                                {item.lifecycle.maintenanceHistory.map((m, i) => (
                                    <div key={i} className="flex justify-between items-center p-4 bg-gray-50 rounded-2xl border border-gray-100">
                                        <div><span className="text-xs font-black text-indigo-900 uppercase">{m.type}</span><span className="ml-3 text-[10px] text-gray-400 font-bold">{m.date}</span></div>
                                        <div className="text-right font-bold text-xs text-indigo-700">{m.technician}</div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const InventoryPanel: React.FC<{
  inventory: InventoryItem[];
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
}> = ({ inventory, setInventory }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [editingItem, setEditingItem] = useState<InventoryItem | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [selectedLifecycleItem, setSelectedLifecycleItem] = useState<InventoryItem | null>(null);

  const filteredInventory = useMemo(() => 
    inventory.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.assignedTo.toLowerCase().includes(searchTerm.toLowerCase())
    ), [inventory, searchTerm]);

  const handleSave = (item: InventoryItem) => {
    if (editingItem) {
      setInventory(prev => prev.map(i => i.id === item.id ? item : i));
      setEditingItem(null);
    } else {
      setInventory(prev => [...prev, item]);
      setIsAdding(false);
    }
  };

  const handleDelete = (id: string) => {
    if (confirm('¿Está seguro de eliminar este equipo del inventario de forma permanente?')) {
      setInventory(prev => prev.filter(i => i.id !== id));
    }
  };

  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 w-full animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
        <div>
            <h1 className="text-3xl font-black text-indigo-900 tracking-tight">Gestión de Inventario</h1>
            <p className="text-sm text-gray-400 font-bold uppercase tracking-widest">Activos y Equipamiento Vuelo Pharma</p>
        </div>
        <div className="flex w-full md:w-auto gap-4">
          <input
            type="text"
            placeholder="Buscar activo..."
            className="w-full md:w-80 px-5 py-3.5 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 outline-none transition-all shadow-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <button 
            onClick={() => setIsAdding(true)} 
            className="bg-indigo-900 text-white px-8 py-3.5 rounded-2xl font-black hover:bg-indigo-800 transition-all shadow-xl shadow-indigo-100 text-xs uppercase tracking-widest"
          >
            Nuevo Activo
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
        {filteredInventory.map(item => (
          <div key={item.id} className="bg-white rounded-3xl border border-gray-50 overflow-hidden shadow-sm hover:shadow-2xl transition-all group flex flex-col h-full border border-gray-100">
            <div className="relative h-48 overflow-hidden bg-gray-50">
              <img src={item.imageUrl || 'https://via.placeholder.com/600x400?text=SIN+IMAGEN'} alt={item.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
              <div className={`absolute top-4 right-4 px-3 py-1 rounded-xl text-[9px] font-black uppercase tracking-widest shadow-md ${statusColors[item.status]}`}>
                {item.status}
              </div>
            </div>
            <div className="p-6 flex-grow flex flex-col">
              <h3 className="text-lg font-black text-indigo-900 leading-tight mb-4 flex-grow line-clamp-2">{item.name}</h3>
              <div className="space-y-1 mb-6">
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">ID: {item.id}</p>
                <p className="text-xs text-indigo-600 font-bold">RESP: {item.assignedTo}</p>
              </div>
              <div className="grid grid-cols-3 gap-2">
                <button onClick={() => setEditingItem(item)} className="p-2 bg-gray-50 text-gray-400 rounded-xl hover:bg-indigo-900 hover:text-white transition-all flex items-center justify-center" title="Editar">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                </button>
                <button onClick={() => setSelectedLifecycleItem(item)} className="p-2 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center" title="Ficha Técnica">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                </button>
                <button onClick={() => handleDelete(item.id)} className="p-2 bg-red-50 text-red-400 rounded-xl hover:bg-red-600 hover:text-white transition-all flex items-center justify-center" title="Borrar">
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {(isAdding || editingItem) && (
        <ItemFormModal
          item={editingItem}
          onClose={() => { setEditingItem(null); setIsAdding(false); }}
          onSave={handleSave}
        />
      )}

      {selectedLifecycleItem && (
          <LifecycleSheetModal 
            item={selectedLifecycleItem} 
            onClose={() => setSelectedLifecycleItem(null)}
            onSave={(itemId, data) => {
              setInventory(prev => prev.map(i => i.id === itemId ? { ...i, lifecycle: data } : i));
              setSelectedLifecycleItem(null);
            }}
          />
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 10px; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        .animate-fadeIn { animation: fadeIn 0.4s ease-out; }
      `}</style>
    </div>
  );
};

