import React, { useState, useMemo, useRef, useCallback, useEffect } from 'react';
import { ScheduleEntry, MaintenanceStatus, InventoryItem } from '../types';
import Logo from './Logo';

declare const html2canvas: any;
declare global {
  interface Window {
    jspdf: any;
  }
}

const MONTHS = ['ENERO', 'FEBRERO', 'MARZO', 'ABRIL', 'MAYO', 'JUNIO', 'JULIO', 'AGOSTO', 'SEPTIEMBRE', 'OCTUBRE', 'NOVIEMBRE', 'DICIEMBRE'];
const YEAR_OPTIONS = ['2024', '2025', '2026', '2027', '2028', '2029', '2030'];

interface MaintenanceScheduleProps {
  schedule: ScheduleEntry[];
  setSchedule: React.Dispatch<React.SetStateAction<ScheduleEntry[]>>;
  inventory: InventoryItem[];
  selectedYear: string;
  setSelectedYear: (year: string) => void;
  readOnly?: boolean;
}

const MaintenanceSchedule: React.FC<MaintenanceScheduleProps> = ({ schedule, setSchedule, inventory, selectedYear, setSelectedYear, readOnly = false }) => {
  const [newEntry, setNewEntry] = useState({ inventoryId: '', actividad: '', respMantenimiento: 'Mauricio Pino', frecuencia: '30-45 dias' });
  const [showAddForm, setShowAddForm] = useState(false);
  const printRef = useRef<HTMLDivElement>(null);

  const handleStatusChange = (id: number, month: string) => {
    if (readOnly) return;
    setSchedule(prev => prev.map(entry => {
      if (entry.id === id) {
        const newStatus = { ...entry.status };
        const current = newStatus[month];
        if (current === MaintenanceStatus.Planned) newStatus[month] = MaintenanceStatus.Realized;
        else if (current === MaintenanceStatus.Realized) delete newStatus[month];
        else newStatus[month] = MaintenanceStatus.Planned;
        return { ...entry, status: newStatus };
      }
      return entry;
    }));
  };

  const handleExport = async () => {
    const { jsPDF } = window.jspdf;
    const element = printRef.current;
    if (element) {
        const canvas = await html2canvas(element, { scale: 3, useCORS: true });
        const data = canvas.toDataURL('image/png');
        const pdf = new jsPDF({ orientation: 'l', unit: 'mm', format: 'letter' });
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const imgWidth = pdfWidth - 20;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;
        pdf.addImage(data, 'PNG', 10, 10, imgWidth, imgHeight);
        pdf.save(`RMATI-02-programa-${selectedYear}.pdf`);
    }
  };

  const monthlyTotals = useMemo(() => {
    return MONTHS.map(month => {
      const planned = schedule.reduce((acc, entry) => acc + (entry.status[month] ? 1 : 0), 0);
      const realized = schedule.reduce((acc, entry) => acc + (entry.status[month] === MaintenanceStatus.Realized ? 1 : 0), 0);
      return { month, planned, realized, compliance: planned > 0 ? (realized / planned) * 100 : 0 };
    });
  }, [schedule]);

  return (
    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 w-full animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 border-b border-indigo-50 pb-6">
        <div>
          <h1 className="text-2xl font-bold text-indigo-900">Programa Anual de Mantenimientos</h1>
          <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">Soporte Técnico de Infraestructura</p>
        </div>
        <div className="flex items-center gap-4 bg-indigo-50/50 p-2 rounded-xl border border-indigo-100">
          <select value={selectedYear} onChange={(e) => setSelectedYear(e.target.value)} className="bg-white border-2 border-indigo-200 text-indigo-900 font-black rounded-lg px-4 py-2 outline-none">
            {YEAR_OPTIONS.map(year => <option key={year} value={year}>{year}</option>)}
          </select>
        </div>
      </div>

      <div ref={printRef} className="overflow-x-auto">
        <div className="mb-4 flex justify-between items-end">
            <Logo className="h-12" />
            <table className="border-collapse border border-gray-300 text-[10px] w-48 bg-white">
                <tbody>
                    <tr><td className="border border-gray-300 p-1 font-bold bg-gray-50 uppercase">CÓDIGO</td><td className="border border-gray-300 p-1 font-black">RMATI-02</td></tr>
                    <tr><td className="border border-gray-300 p-1 font-bold bg-gray-50 uppercase">VERSIÓN</td><td className="border border-gray-300 p-1 font-black">02</td></tr>
                    <tr><td className="border border-gray-300 p-1 font-bold bg-gray-50 uppercase">AÑO</td><td className="border border-gray-300 p-1 font-black">{selectedYear}</td></tr>
                </tbody>
            </table>
        </div>

        <table className="min-w-full border-collapse border border-gray-200 text-xs">
          <thead className="bg-indigo-900 text-white font-bold uppercase tracking-tighter text-[9px]">
            <tr>
              <th className="border border-indigo-800 p-2 w-48">Equipo / Activo</th>
              <th className="border border-indigo-800 p-2 w-48">Actividad</th>
              <th className="border border-indigo-800 p-2 w-32">Responsable</th>
              {MONTHS.map(m => <th key={m} className="border border-indigo-800 p-1 w-10 text-center">{m.substring(0,3)}</th>)}
            </tr>
          </thead>
          <tbody className="bg-white">
            {schedule.map(entry => (
              <tr key={entry.id} className="hover:bg-indigo-50/30 transition-colors">
                <td className="border border-gray-200 p-2 font-bold text-indigo-900">{entry.equipo}</td>
                <td className="border border-gray-200 p-2 text-gray-600 italic">{entry.actividad}</td>
                <td className="border border-gray-200 p-2 text-[10px] font-black uppercase text-gray-400">{entry.respMantenimiento}</td>
                {MONTHS.map(m => (
                  <td key={m} className="border border-gray-200 p-1 text-center">
                    <button 
                      onClick={() => handleStatusChange(entry.id, m)}
                      className={`w-6 h-6 rounded flex items-center justify-center mx-auto text-[10px] font-black transition-all ${
                        entry.status[m] === MaintenanceStatus.Planned ? 'bg-indigo-500 text-white shadow-md' :
                        entry.status[m] === MaintenanceStatus.Realized ? 'bg-[#00E5FF] text-white shadow-md' : 'bg-gray-50 text-gray-200'
                      }`}
                    >
                      {entry.status[m] || ''}
                    </button>
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
          <tfoot className="bg-gray-50 font-black text-[9px] uppercase">
            <tr>
              <td colSpan={3} className="border border-gray-200 p-2 text-right">Programados (P)</td>
              {monthlyTotals.map(t => <td key={t.month} className="border border-gray-200 p-1 text-center text-indigo-900">{t.planned}</td>)}
            </tr>
            <tr>
              <td colSpan={3} className="border border-gray-200 p-2 text-right">Realizados (R)</td>
              {monthlyTotals.map(t => <td key={t.month} className="border border-gray-200 p-1 text-center text-[#00E5FF]">{t.realized}</td>)}
            </tr>
          </tfoot>
        </table>
      </div>

      <div className="mt-8 flex gap-3">
        {!readOnly && (
           <button onClick={() => setShowAddForm(!showAddForm)} className="px-6 py-2 bg-indigo-900 text-white text-xs font-black uppercase rounded-xl shadow-lg">Agregar Tarea</button>
        )}
        <button onClick={handleExport} className="px-6 py-2 bg-white border border-gray-200 text-indigo-900 text-xs font-black uppercase rounded-xl">Exportar PDF</button>
      </div>

      {showAddForm && !readOnly && (
        <form className="mt-4 p-4 border-2 border-dashed border-indigo-100 rounded-2xl bg-indigo-50/30 flex gap-4" onSubmit={(e) => {
          e.preventDefault();
          const item = inventory.find(i => i.id === newEntry.inventoryId);
          if (item) {
             setSchedule([...schedule, { id: Date.now(), equipo: item.name, modelo: item.model, actividad: newEntry.actividad, respMantenimiento: newEntry.respMantenimiento, respEquipo: item.assignedTo, frecuencia: newEntry.frecuencia, status: {} }]);
             setShowAddForm(false);
          }
        }}>
           <select className="flex-1 p-2 border rounded-lg text-xs" onChange={e => setNewEntry({...newEntry, inventoryId: e.target.value})} required>
              <option value="">Seleccione Equipo...</option>
              {inventory.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
           </select>
           <input className="flex-1 p-2 border rounded-lg text-xs" placeholder="Actividad..." onChange={e => setNewEntry({...newEntry, actividad: e.target.value})} required />
           <button type="submit" className="px-6 py-2 bg-indigo-600 text-white text-xs font-black uppercase rounded-xl">Guardar</button>
        </form>
      )}
    </div>
  );
};

export default MaintenanceSchedule;

import React, { useState, useMemo, useRef } from 'react';
import { InventoryItem, InventoryStatus, LifecycleData } from '../types';
import Logo from './Logo';

declare const html2canvas: any;
declare global {
  interface Window {
    jspdf: any;
  }
}

const statusColors: { [key in InventoryStatus]: string } = {
  [InventoryStatus.InUse]: 'bg-green-100 text-green-800',
  [InventoryStatus.InStorage]: 'bg-blue-100 text-blue-800',
  [InventoryStatus.UnderMaintenance]: 'bg-yellow-100 text-yellow-800',
  [InventoryStatus.Decommissioned]: 'bg-red-100 text-red-800',
};

const InventoryPanel: React.FC<{
  inventory: InventoryItem[];
  setInventory: React.Dispatch<React.SetStateAction<InventoryItem[]>>;
  readOnly?: boolean;
}> = ({ inventory, setInventory, readOnly = false }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const filteredInventory = useMemo(() => 
    inventory.filter(item => 
      item.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.id.toLowerCase().includes(searchTerm.toLowerCase())
    ), [inventory, searchTerm]);

  const handleExportCSV = () => {
    const headers = "ID,Nombre,Categoria,Modelo,Serial,Responsable,FechaCompra,Estado\n";
    const rows = inventory.map(i => 
      `${i.id},${i.name},${i.category},${i.model},${i.serial},${i.assignedTo},${i.purchaseDate},${i.status}`
    ).join("\n");

    const blob = new Blob([headers + rows], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.setAttribute("href", url);
    link.setAttribute("download", `inventario_vuelo_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleImportCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split("\n").slice(1); // Saltar encabezado
      const newItems: InventoryItem[] = lines.filter(l => l.trim() !== "").map(line => {
        const [id, name, category, model, serial, assignedTo, purchaseDate, status] = line.split(",");
        return {
          id: id || `EQ-${Math.random().toString(36).substr(2,6).toUpperCase()}`,
          name: name || "Sin nombre",
          category: category || "General",
          model: model || "N/A",
          serial: serial || "N/A",
          assignedTo: assignedTo || "Sin asignar",
          purchaseDate: purchaseDate || new Date().toISOString().split('T')[0],
          status: (status as InventoryStatus) || InventoryStatus.InStorage,
          imageUrl: '',
          lifecycle: { characteristics: '', maintenanceHistory: [], usageHistory: '', observations: '' }
        };
      });
      setInventory(prev => [...prev, ...newItems]);
      alert(`${newItems.length} equipos importados con éxito.`);
    };
    reader.readAsText(file);
  };

  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 w-full animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-6">
        <div>
            <h1 className="text-3xl font-black text-indigo-900 tracking-tight">Gestión de Inventario</h1>
            <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">Control Maestro de Activos Fijos</p>
        </div>
        <div className="flex w-full md:w-auto gap-4">
          <input
            type="text"
            placeholder="Buscar activo..."
            className="w-full md:w-64 px-5 py-3.5 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all shadow-sm"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          {!readOnly && (
            <>
              <button onClick={() => fileInputRef.current?.click()} className="bg-white border border-gray-200 text-indigo-900 px-6 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-gray-50 transition-all">Importar CSV</button>
              <input type="file" ref={fileInputRef} className="hidden" accept=".csv" onChange={handleImportCSV} />
            </>
          )}
          <button onClick={handleExportCSV} className="bg-green-600 text-white px-6 py-3.5 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-green-100 hover:bg-green-700 transition-all">Excel (CSV)</button>
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
        {filteredInventory.map(item => (
          <div key={item.id} className="bg-white rounded-3xl border border-gray-50 overflow-hidden shadow-sm hover:shadow-2xl transition-all group flex flex-col h-full border border-gray-100 p-6 relative">
            <div className={`absolute top-4 right-4 px-3 py-1 rounded-xl text-[9px] font-black uppercase tracking-widest ${statusColors[item.status]}`}>
                {item.status}
            </div>
            <p className="text-[10px] text-indigo-400 font-black uppercase tracking-[0.2em] mb-1">{item.category}</p>
            <h3 className="text-lg font-black text-indigo-900 leading-tight line-clamp-2 min-h-[3.5rem]">{item.name}</h3>
            <div className="mt-4 space-y-2 text-xs font-bold text-gray-500 flex-grow">
               <p><span className="text-gray-300">ID:</span> {item.id}</p>
               <p><span className="text-gray-300">RESP:</span> {item.assignedTo}</p>
            </div>
            <div className="mt-6">
               <button className="w-full py-3 bg-indigo-50 text-indigo-900 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-900 hover:text-white transition-all">Ver Ficha Técnica</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

