import React, { useState, useEffect } from 'react';
import Logo from './components/Logo';
import MaintenanceRecord from './components/MaintenanceRecord';
import MaintenanceSchedule from './components/MaintenanceSchedule';
import InventoryPanel from './components/InventoryPanel';
import HistoryPanel from './components/HistoryPanel';
import IndicatorsPanel from './components/IndicatorsPanel';
import { InventoryItem, InventoryStatus, ScheduleEntry, MaintenanceStatus, MaintenanceRecordHistory, User, UserRole } from './types';

const INITIAL_USERS: User[] = [
  { id: '1', username: 'areati', password: 'Vuelopharma2026*', role: UserRole.Admin },
  { id: '2', username: 'administrativos', password: 'Vuelopharma2026*', role: UserRole.Viewer }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('schedule');
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('vuelo_current_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('vuelo_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [selectedYear, setSelectedYear] = useState<string>(new Date().getFullYear().toString());

  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('vuelo_inventory');
    return saved ? JSON.parse(saved) : [];
  });

  const [allSchedules, setAllSchedules] = useState<Record<string, ScheduleEntry[]>>(() => {
    const saved = localStorage.getItem('vuelo_schedules');
    return saved ? JSON.parse(saved) : {};
  });

  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Guardado Automático en LocalStorage
  useEffect(() => {
    localStorage.setItem('vuelo_users', JSON.stringify(users));
    localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
    localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
    if (currentUser) localStorage.setItem('vuelo_current_user', JSON.stringify(currentUser));
  }, [users, inventory, allSchedules, currentUser]);

  const handleGlobalSave = () => {
    setSaveStatus('saving');
    localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
    localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
    localStorage.setItem('vuelo_users', JSON.stringify(users));

    setTimeout(() => {
      setSaveStatus('saved');
      setTimeout(() => setSaveStatus('idle'), 2000);
    }, 8000);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (user) setCurrentUser(user);
    else alert('Credenciales incorrectas');
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('vuelo_current_user');
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-indigo-900 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-800 via-indigo-950 to-black">
        <div className="bg-white p-10 rounded-[3rem] shadow-2xl w-full max-w-md animate-fadeIn border border-indigo-500/20">
          <div className="text-center mb-8">
            <Logo className="h-24 mx-auto" />
            <h2 className="text-2xl font-black text-indigo-900 mt-8 uppercase tracking-widest">Portal de Calidad</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.3em] mt-2">Vuelo Pharma Colombia</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-5">
            <input 
              type="text" 
              placeholder="Usuario" 
              className="w-full p-4 bg-gray-50 border-2 border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 outline-none font-bold"
              value={loginForm.username}
              onChange={e => setLoginForm({...loginForm, username: e.target.value})}
            />
            <input 
              type="password" 
              placeholder="Contraseña" 
              className="w-full p-4 bg-gray-50 border-2 border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 outline-none font-bold"
              value={loginForm.password}
              onChange={e => setLoginForm({...loginForm, password: e.target.value})}
            />
            <button className="w-full py-4 bg-indigo-900 text-white font-black rounded-2xl uppercase tracking-[0.2em] shadow-xl hover:-translate-y-1 transition-all">Ingresar</button>
          </form>
        </div>
      </div>
    );
  }

  const isAdmin = currentUser.role === UserRole.Admin;

  return (
    <div className="min-h-screen bg-gray-50 font-sans">
      <header className="bg-white shadow-md border-b-4 border-indigo-900 px-8 py-4 flex justify-between items-center sticky top-0 z-50">
         <Logo className="h-14" />
         <div className="flex items-center gap-4">
            {isAdmin && (
              <button 
                onClick={handleGlobalSave}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${
                  saveStatus === 'saving' ? 'bg-yellow-500 text-white animate-pulse' :
                  saveStatus === 'saved' ? 'bg-green-600 text-white' : 'bg-indigo-900 text-white hover:bg-indigo-800'
                }`}
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" /></svg>
                {saveStatus === 'saving' ? 'Guardando...' : saveStatus === 'saved' ? '¡Guardado!' : 'Guardar Cambios'}
              </button>
            )}
            <div className="text-right hidden md:block border-l pl-4 border-gray-100">
               <p className="text-xs font-black text-indigo-900 uppercase leading-none">{currentUser.username}</p>
               <p className="text-[10px] text-indigo-400 font-bold uppercase">{isAdmin ? 'ADMIN' : 'VISUALIZADOR'}</p>
            </div>
            <button onClick={handleLogout} className="p-2.5 bg-red-50 text-red-600 rounded-xl hover:bg-red-600 hover:text-white transition-all">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
            </button>
         </div>
      </header>

      <main className="p-8 container mx-auto">
        <nav className="flex flex-wrap gap-2 mb-8 bg-white p-2 rounded-2xl border border-indigo-50 shadow-sm">
           <TabBtn active={activeTab === 'schedule'} label="Programa Anual" onClick={() => setActiveTab('schedule')} />
           <TabBtn active={activeTab === 'indicators'} label="Indicadores" onClick={() => setActiveTab('indicators')} />
           <TabBtn active={activeTab === 'inventory'} label="Inventario" onClick={() => setActiveTab('inventory')} />
           <TabBtn active={activeTab === 'history'} label="Trazabilidad" onClick={() => setActiveTab('history')} />
           {isAdmin && <TabBtn active={activeTab === 'record'} label="Registrar Mantenimiento" onClick={() => setActiveTab('record')} />}
           {isAdmin && <TabBtn active={activeTab === 'users'} label="Usuarios" onClick={() => setActiveTab('users')} />}
        </nav>

        {activeTab === 'schedule' && (
           <MaintenanceSchedule 
              schedule={allSchedules[selectedYear] || []} 
              setSchedule={(s) => setAllSchedules({...allSchedules, [selectedYear]: typeof s === 'function' ? s(allSchedules[selectedYear] || []) : s})}
              inventory={inventory}
              selectedYear={selectedYear}
              setSelectedYear={setSelectedYear}
              readOnly={!isAdmin}
           />
        )}
        {activeTab === 'indicators' && <IndicatorsPanel inventory={inventory} schedule={allSchedules[selectedYear] || []} />}
        {activeTab === 'inventory' && <InventoryPanel inventory={inventory} setInventory={setInventory} readOnly={!isAdmin} />}
        {activeTab === 'history' && <HistoryPanel inventory={inventory} />}
        {isAdmin && activeTab === 'record' && (
           <MaintenanceRecord inventory={inventory} addMaintenanceToHistory={(id, h) => {
              setInventory(prev => prev.map(i => i.id === id ? {...i, lifecycle: {...i.lifecycle, maintenanceHistory: [...i.lifecycle.maintenanceHistory, h]}} : i));
           }} />
        )}
        {isAdmin && activeTab === 'users' && (
          <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm animate-fadeIn">
             <h2 className="text-xl font-black text-indigo-900 uppercase mb-6 tracking-tighter">Gestión de Usuarios</h2>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {users.map(u => (
                  <div key={u.id} className="p-6 bg-gray-50 rounded-3xl flex justify-between items-center border border-gray-100">
                     <div>
                        <p className="font-black text-indigo-900">{u.username}</p>
                        <p className="text-[10px] text-gray-400 font-bold uppercase">{u.role}</p>
                     </div>
                     {u.username !== currentUser.username && (
                       <button className="text-red-500 font-bold text-xs" onClick={() => setUsers(users.filter(usr => usr.id !== u.id))}>Eliminar</button>
                     )}
                  </div>
                ))}
                <button className="p-6 border-2 border-dashed border-indigo-100 rounded-3xl text-indigo-400 font-black uppercase text-xs hover:bg-indigo-50" onClick={() => {
                  const name = prompt('Nombre de usuario:');
                  const pass = prompt('Contraseña:');
                  if(name && pass) setUsers([...users, { id: Date.now().toString(), username: name, password: pass, role: UserRole.Viewer }]);
                }}>+ Crear Nuevo Usuario</button>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

const TabBtn = ({ active, label, onClick }: any) => (
  <button onClick={onClick} className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${active ? 'bg-indigo-900 text-white shadow-xl translate-y-[-2px]' : 'text-indigo-400 hover:text-indigo-900 hover:bg-indigo-50'}`}>{label}</button>
);

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { ScheduleEntry, MaintenanceStatus, InventoryItem } from '../types';
import Logo from './Logo';

declare const html2canvas: any;
declare global {
  interface Window {
    jspdf: any;
  }
}

const MONTHS = ['ENERO', 'FEBRERO', 'MARZO', 'ABRIL', 'MAYO', 'JUNIO', 'JULIO', 'AGOSTO', 'SEPTIEMBRE', 'OCTUBRE', 'NOVIEMBRE', 'DICIEMBRE'];
const YEAR_OPTIONS = ['2024', '2025', '2026', '2027', '2028', '2029', '2030'];

interface MaintenanceScheduleProps {
  schedule: ScheduleEntry[];
  setSchedule: React.Dispatch<React.SetStateAction<ScheduleEntry[]>>;
  inventory: InventoryItem[];
  selectedYear: string;
  setSelectedYear: (year: string) => void;
  readOnly?: boolean;
}

const MaintenanceSchedule: React.FC<MaintenanceScheduleProps> = ({ schedule, setSchedule, inventory, selectedYear, setSelectedYear, readOnly = false }) => {
  const [newEntry, setNewEntry] = useState({ inventoryId: '', actividad: '', respMantenimiento: 'Mauricio Pino', frecuencia: '30-45 dias' });
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingId, setEditingId] = useState<number | null>(null);

  // Codificación editable
  const [formatCode, setFormatCode] = useState(() => localStorage.getItem('vuelo_sched_code') || 'RMATI-02');
  const [formatVersion, setFormatVersion] = useState(() => localStorage.getItem('vuelo_sched_version') || '02');

  useEffect(() => {
    localStorage.setItem('vuelo_sched_code', formatCode);
    localStorage.setItem('vuelo_sched_version', formatVersion);
  }, [formatCode, formatVersion]);

  const printRef = useRef<HTMLDivElement>(null);

  const handleStatusChange = (id: number, month: string) => {
    if (readOnly) return;
    setSchedule(prev => prev.map(entry => {
      if (entry.id === id) {
        const newStatus = { ...entry.status };
        const current = newStatus[month];
        if (current === MaintenanceStatus.Planned) newStatus[month] = MaintenanceStatus.Realized;
        else if (current === MaintenanceStatus.Realized) delete newStatus[month];
        else newStatus[month] = MaintenanceStatus.Planned;
        return { ...entry, status: newStatus };
      }
      return entry;
    }));
  };

  const handleExport = async () => {
    const { jsPDF } = window.jspdf;
    const element = printRef.current;
    if (element) {
        const canvas = await html2canvas(element, { 
          scale: 3, 
          useCORS: true,
          logging: false,
          backgroundColor: "#FFFFFF"
        });
        const data = canvas.toDataURL('image/png');
        const pdf = new jsPDF({ orientation: 'l', unit: 'mm', format: 'letter' });
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const imgWidth = pdfWidth - 20;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;
        pdf.addImage(data, 'PNG', 10, 10, imgWidth, imgHeight);
        pdf.save(`${formatCode}-programa-${selectedYear}.pdf`);
    }
  };

  const handleDeleteRow = (id: number) => {
    if (confirm('¿Eliminar esta tarea del programa anual?')) {
      setSchedule(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleEditRow = (entry: ScheduleEntry) => {
    setEditingId(entry.id);
    setNewEntry({
      inventoryId: '', // No cambiamos el equipo por ID para evitar desconfiguración, solo texto
      actividad: entry.actividad,
      respMantenimiento: entry.respMantenimiento,
      frecuencia: entry.frecuencia
    });
    setShowAddForm(true);
  };

  const monthlyTotals = useMemo(() => {
    return MONTHS.map(month => {
      const planned = schedule.reduce((acc, entry) => acc + (entry.status[month] ? 1 : 0), 0);
      const realized = schedule.reduce((acc, entry) => acc + (entry.status[month] === MaintenanceStatus.Realized ? 1 : 0), 0);
      return { month, planned, realized, compliance: planned > 0 ? (realized / planned) * 100 : 0 };
    });
  }, [schedule]);

  return (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 w-full animate-fadeIn">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4 border-b border-indigo-50 pb-6">
        <div>
          <h1 className="text-3xl font-black text-indigo-900 uppercase tracking-tighter">Programa Anual de Mantenimiento</h1>
          <p className="text-[10px] text-indigo-400 font-black uppercase tracking-[0.4em] mt-1">Soporte Técnico de Infraestructura</p>
        </div>
        <div className="flex items-center gap-4 bg-gray-50 p-3 rounded-2xl border border-gray-100">
          <label className="text-[9px] font-black uppercase text-gray-400">Año de Gestión:</label>
          <select value={selectedYear} onChange={(e) => setSelectedYear(e.target.value)} className="bg-white border-2 border-indigo-100 text-indigo-900 font-black rounded-xl px-4 py-2 outline-none">
            {YEAR_OPTIONS.map(year => <option key={year} value={year}>{year}</option>)}
          </select>
        </div>
      </div>

      <div ref={printRef} className="overflow-x-auto p-4 bg-white rounded-xl">
        <div className="mb-6 flex justify-between items-center">
            <Logo className="h-16" />
            <div className="text-center flex-grow mx-10">
                <h2 className="text-2xl font-black text-indigo-900 uppercase tracking-tighter">Programa Anual de Mantenimiento Preventivo</h2>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">Activos Críticos de Planta</p>
            </div>
            <table className="border-collapse border border-gray-300 text-[10px] w-56 bg-white shadow-sm">
                <tbody>
                    <tr>
                      <td className="border border-gray-300 p-2 font-black bg-gray-50 uppercase text-[8px]">CÓDIGO</td>
                      <td className="border border-gray-300 p-2">
                        {readOnly ? <span className="font-black">{formatCode}</span> : 
                        <input className="w-full bg-transparent font-black outline-none border-b border-transparent focus:border-indigo-300" value={formatCode} onChange={e => setFormatCode(e.target.value)} />}
                      </td>
                    </tr>
                    <tr>
                      <td className="border border-gray-300 p-2 font-black bg-gray-50 uppercase text-[8px]">VERSIÓN</td>
                      <td className="border border-gray-300 p-2">
                        {readOnly ? <span className="font-black">{formatVersion}</span> : 
                        <input className="w-full bg-transparent font-black outline-none border-b border-transparent focus:border-indigo-300" value={formatVersion} onChange={e => setFormatVersion(e.target.value)} />}
                      </td>
                    </tr>
                    <tr>
                      <td className="border border-gray-300 p-2 font-black bg-gray-50 uppercase text-[8px]">VIGENCIA</td>
                      <td className="border border-gray-300 p-2 font-black">{selectedYear}</td>
                    </tr>
                </tbody>
            </table>
        </div>

        <table className="min-w-full border-collapse border border-gray-200 text-xs">
          <thead className="bg-indigo-900 text-white font-bold uppercase tracking-tighter text-[8px]">
            <tr>
              {!readOnly && <th className="border border-indigo-800 p-2 w-10">...</th>}
              <th className="border border-indigo-800 p-2 w-48 text-left">Equipo / Activo Fijo</th>
              <th className="border border-indigo-800 p-2 w-48 text-left">Actividad Técnica</th>
              <th className="border border-indigo-800 p-2 w-32 text-left">Responsable</th>
              {MONTHS.map(m => <th key={m} className="border border-indigo-800 p-1 w-12 text-center">{m.substring(0,3)}</th>)}
            </tr>
          </thead>
          <tbody className="bg-white">
            {schedule.map(entry => (
              <tr key={entry.id} className="hover:bg-indigo-50/20 transition-colors">
                {!readOnly && (
                  <td className="border border-gray-200 p-1 text-center">
                    <div className="flex gap-1 justify-center">
                      <button onClick={() => handleEditRow(entry)} className="text-indigo-400 hover:text-indigo-900">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                      </button>
                      <button onClick={() => handleDeleteRow(entry.id)} className="text-red-300 hover:text-red-600">
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                    </div>
                  </td>
                )}
                <td className="border border-gray-200 p-2 font-black text-indigo-900 text-[10px] uppercase">{entry.equipo}</td>
                <td className="border border-gray-200 p-2 text-gray-600 italic text-[10px]">{entry.actividad}</td>
                <td className="border border-gray-200 p-2 text-[9px] font-black uppercase text-gray-400">{entry.respMantenimiento}</td>
                {MONTHS.map(m => (
                  <td key={m} className="border border-gray-200 p-1 text-center">
                    <button 
                      onClick={() => handleStatusChange(entry.id, m)}
                      className={`w-7 h-7 rounded-lg flex items-center justify-center mx-auto text-[9px] font-black transition-all ${
                        entry.status[m] === MaintenanceStatus.Planned ? 'bg-indigo-500 text-white shadow-md' :
                        entry.status[m] === MaintenanceStatus.Realized ? 'bg-[#00E5FF] text-white shadow-md' : 'bg-gray-50 text-gray-200'
                      }`}
                    >
                      {entry.status[m] || ''}
                    </button>
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
          <tfoot className="bg-gray-50 font-black text-[8px] uppercase">
            <tr className="border-t-2 border-indigo-900">
              <td colSpan={isAdmin ? 4 : 3} className="border border-gray-200 p-2 text-right">Programados Total (P)</td>
              {monthlyTotals.map(t => <td key={t.month} className="border border-gray-200 p-1 text-center text-indigo-900 font-black">{t.planned}</td>)}
            </tr>
            <tr>
              <td colSpan={isAdmin ? 4 : 3} className="border border-gray-200 p-2 text-right">Ejecutados Total (R)</td>
              {monthlyTotals.map(t => <td key={t.month} className="border border-gray-200 p-1 text-center text-[#00E5FF] font-black">{t.realized}</td>)}
            </tr>
          </tfoot>
        </table>
      </div>

      <div className="mt-8 flex gap-3">
        {!readOnly && (
           <button onClick={() => { setEditingId(null); setShowAddForm(!showAddForm); }} className="px-8 py-3 bg-indigo-900 text-white text-[10px] font-black uppercase tracking-widest rounded-2xl shadow-xl shadow-indigo-100 hover:-translate-y-1 transition-all">Nueva Tarea</button>
        )}
        <button onClick={handleExport} className="px-8 py-3 bg-white border-2 border-indigo-100 text-indigo-900 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-gray-50 transition-all">Exportar Formato PDF</button>
      </div>

      {showAddForm && !readOnly && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <form className="bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-lg animate-fadeIn border border-indigo-50" onSubmit={(e) => {
            e.preventDefault();
            if (editingId) {
              setSchedule(prev => prev.map(e => e.id === editingId ? { ...e, actividad: newEntry.actividad, respMantenimiento: newEntry.respMantenimiento, frecuencia: newEntry.frecuencia } : e));
            } else {
              const item = inventory.find(i => i.id === newEntry.inventoryId);
              if (item) {
                 setSchedule([...schedule, { id: Date.now(), equipo: item.name, modelo: item.model, actividad: newEntry.actividad, respMantenimiento: newEntry.respMantenimiento, respEquipo: item.assignedTo, frecuencia: newEntry.frecuencia, status: {} }]);
              }
            }
            setShowAddForm(false);
            setEditingId(null);
