             <div className="mt-8 flex justify-end gap-3">
               <button type="button" onClick={() => { setShowAddForm(false); setEditingId(null); }} className="px-6 py-3 bg-gray-100 text-gray-500 text-[10px] font-black uppercase rounded-xl">Cancelar</button>
               <button type="submit" className="px-8 py-3 bg-indigo-900 text-white text-[10px] font-black uppercase rounded-xl shadow-lg">Guardar Registro</button>
             </div>
          </form>
        </div>
