  );
};

export default MaintenanceSchedule;

import React, { useState, useEffect, useCallback } from 'react';
import Logo from './components/Logo';
import MaintenanceRecord from './components/MaintenanceRecord';
import MaintenanceSchedule from './components/MaintenanceSchedule';
import InventoryPanel from './components/InventoryPanel';
import HistoryPanel from './components/HistoryPanel';
import IndicatorsPanel from './components/IndicatorsPanel';
import { InventoryItem, InventoryStatus, ScheduleEntry, User, UserRole } from './types';

const INITIAL_USERS: User[] = [
  { id: '1', username: 'areati', password: 'Vuelopharma2026*', role: UserRole.Admin },
  { id: '2', username: 'administrativos', password: 'Vuelopharma2026*', role: UserRole.Viewer }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('schedule');
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('vuelo_current_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('vuelo_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [selectedYear, setSelectedYear] = useState<string>(new Date().getFullYear().toString());

  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [allSchedules, setAllSchedules] = useState<Record<string, ScheduleEntry[]>>({});
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // EFECTO DE MIGRACIÓN Y CARGA INICIAL
  useEffect(() => {
    // 1. Cargar datos existentes
    const savedInv = localStorage.getItem('vuelo_inventory');
    const savedSch = localStorage.getItem('vuelo_schedules');

    let parsedInv: InventoryItem[] = savedInv ? JSON.parse(savedInv) : [];
    let parsedSch = savedSch ? JSON.parse(savedSch) : {};

    // 2. Migración: Asegurar que todos los items tengan la estructura Lifecycle nueva
    const migratedInv = parsedInv.map(item => ({
      ...item,
      lifecycle: item.lifecycle || { 
        characteristics: '', 
        maintenanceHistory: [], 
        usageHistory: '', 
        observations: '' 
      }
    }));

    setInventory(migratedInv);
    setAllSchedules(parsedSch);
  }, []);

  // Guardado Automático Persistente
  useEffect(() => {
    if (inventory.length > 0) localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
    if (Object.keys(allSchedules).length > 0) localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
    localStorage.setItem('vuelo_users', JSON.stringify(users));
    if (currentUser) localStorage.setItem('vuelo_current_user', JSON.stringify(currentUser));
  }, [inventory, allSchedules, users, currentUser]);

  const handleGlobalSave = useCallback(() => {
    setSaveStatus('saving');
    try {
      localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
      localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
      localStorage.setItem('vuelo_users', JSON.stringify(users));

      setTimeout(() => {
        setSaveStatus('saved');
        setTimeout(() => setSaveStatus('idle'), 2000);
      }, 1000);
    } catch (e) {
      alert("Error al guardar: Posiblemente el almacenamiento está lleno.");
      setSaveStatus('idle');
    }
  }, [inventory, allSchedules, users]);

  const handleExportFullBackup = () => {
    const data = {
      inventory,
      allSchedules,
      users,
      timestamp: new Date().toISOString(),
      app: "Vuelo Pharma Quality Manager"
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `RESPALDO_TOTAL_VUELO_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const handleImportFullBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.inventory && data.allSchedules) {
          if (confirm("¿Estás seguro? Esto reemplazará todos los datos actuales con los del respaldo.")) {
            setInventory(data.inventory);
            setAllSchedules(data.allSchedules);
            if (data.users) setUsers(data.users);
            alert("Restauración completada con éxito.");
          }
        } else {
          alert("El archivo no parece ser un respaldo válido de Vuelo Pharma.");
        }
      } catch (err) {
        alert("Error al leer el archivo de respaldo.");
      }
    };
    reader.readAsText(file);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (user) setCurrentUser(user);
    else alert('Credenciales incorrectas');
  };

  const handleLogout = () => {
    if(confirm("¿Cerrar sesión?")) {
      setCurrentUser(null);
      localStorage.removeItem('vuelo_current_user');
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-slate-950 to-black">
        <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl w-full max-w-md border border-white/10 animate-fadeIn">
          <div className="text-center mb-10">
            <Logo className="h-28 mx-auto" />
            <h2 className="text-2xl font-black text-indigo-950 mt-8 uppercase tracking-widest">Gestión de Calidad</h2>
            <p className="text-[9px] text-gray-400 font-bold uppercase tracking-[0.4em] mt-2">Vuelo Pharma Colombia</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <input 
              type="text" 
              placeholder="USUARIO" 
              className="w-full p-5 bg-gray-50 border-2 border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 outline-none font-black text-xs uppercase tracking-widest"
              value={loginForm.username}
              onChange={e => setLoginForm({...loginForm, username: e.target.value})}
              required
            />
            <input 
              type="password" 
              placeholder="CONTRASEÑA" 
              className="w-full p-5 bg-gray-50 border-2 border-gray-100 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 outline-none font-black text-xs uppercase tracking-widest"
              value={loginForm.password}
              onChange={e => setLoginForm({...loginForm, password: e.target.value})}
              required
            />
            <button className="w-full py-5 bg-indigo-950 text-white font-black rounded-2xl uppercase tracking-[0.3em] shadow-2xl hover:bg-indigo-900 hover:-translate-y-1 transition-all text-xs">
              Autenticar Acceso
            </button>
          </form>
        </div>
