import { InventoryItem, InventoryStatus, ScheduleEntry, User, UserRole } from './types';

const INITIAL_USERS: User[] = [
  { id: '1', username: 'areati', password: 'Vuelopharma2026*', role: UserRole.Admin },
  { id: '2', username: 'administrativos', password: 'Vuelopharma2026*', role: UserRole.Viewer }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('schedule');
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('vuelo_current_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('vuelo_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [selectedYear, setSelectedYear] = useState<string>(new Date().getFullYear().toString());

  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [allSchedules, setAllSchedules] = useState<Record<string, ScheduleEntry[]>>({});
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // MOTOR DE BÚSQUEDA Y RECUPERACIÓN DE DATOS ANTIGUOS
  const recoverLegacyData = useCallback(() => {
    const legacyKeys = ['vuelo_inventory', 'inventory', 'items', 'equipos', 'inventory_items', 'vuelo_items'];
    let recoveredItems: any[] = [];

    legacyKeys.forEach(key => {
      const data = localStorage.getItem(key);
      if (data) {
        try {
          const parsed = JSON.parse(data);
          if (Array.isArray(parsed)) {
            recoveredItems = [...recoveredItems, ...parsed];
          }
        } catch (e) {
          console.warn(`Error al leer clave legacy: ${key}`);
        }
      }
    });

    // Eliminar duplicados por ID
    const uniqueMap = new Map();
    recoveredItems.forEach(item => {
      if (item && item.id) {
        uniqueMap.set(item.id, item);
      }
    });

    const finalInventory: InventoryItem[] = Array.from(uniqueMap.values()).map(item => ({
      id: item.id || `EQ-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
      name: item.name || 'Equipo Recuperado',
      category: item.category || 'General',
      model: item.model || item.marcaModelo || 'N/A',
      serial: item.serial || 'N/A',
      assignedTo: item.assignedTo || item.responsable || 'Sin asignar',
      purchaseDate: item.purchaseDate || new Date().toISOString().split('T')[0],
      status: item.status || InventoryStatus.InStorage,
      imageUrl: item.imageUrl || '',
      lifecycle: item.lifecycle || { 
        characteristics: item.characteristics || '', 
        maintenanceHistory: item.maintenanceHistory || [], 
        usageHistory: item.usageHistory || '', 
        observations: item.observations || '' 
      }
    }));

    if (finalInventory.length > 0) {
      setInventory(finalInventory);
      // Guardar inmediatamente en la nueva clave oficial
      localStorage.setItem('vuelo_inventory', JSON.stringify(finalInventory));
      return finalInventory.length;
    }
    return 0;
  }, []);

  // EFECTO DE CARGA INICIAL CON MIGRACIÓN
  useEffect(() => {
    const count = recoverLegacyData();

    // Cargar programas anuales
    const savedSch = localStorage.getItem('vuelo_schedules');
    if (savedSch) {
      setAllSchedules(JSON.parse(savedSch));
    }

    if (count > 0) {
      console.log(`Sistema: Se han recuperado ${count} activos de sesiones anteriores.`);
