  // Guardado Automático Persistente
  useEffect(() => {
    if (inventory.length > 0) localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
    if (Object.keys(allSchedules).length > 0) localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
    localStorage.setItem('vuelo_users', JSON.stringify(users));
