import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Logo from './components/Logo';
import MaintenanceRecord from './components/MaintenanceRecord';
import MaintenanceSchedule from './components/MaintenanceSchedule';
import InventoryPanel from './components/InventoryPanel';
import HistoryPanel from './components/HistoryPanel';
import IndicatorsPanel from './components/IndicatorsPanel';
import { InventoryItem, InventoryStatus, ScheduleEntry, User, UserRole } from './types';

const INITIAL_USERS: User[] = [
  { id: '1', username: 'areati', password: 'Vuelopharma2026*', role: UserRole.Admin },
  { id: '2', username: 'administrativos', password: 'Vuelopharma2026*', role: UserRole.Viewer }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('inventory');
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('vuelo_current_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('vuelo_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [selectedYear, setSelectedYear] = useState<string>(new Date().getFullYear().toString());

  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [allSchedules, setAllSchedules] = useState<Record<string, ScheduleEntry[]>>({});
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  /**
   * MOTOR DE RECUPERACIÓN MAESTRO:
   * Busca en TODAS las posibles ubicaciones de memoria de sesiones anteriores.
   */
  const performDeepDataRecovery = useCallback(() => {
    // Lista de claves utilizadas en versiones previas de la app para no perder nada
    const legacyKeys = [
      'vuelo_inventory', 
      'inventory', 
      'items', 
      'equipos', 
      'inventory_items', 
      'vuelo_items', 
      'vuelo_data_backup',
      'quality_manager_data'
    ];

    let allFoundItems: any[] = [];

    legacyKeys.forEach(key => {
      const data = localStorage.getItem(key);
      if (data) {
        try {
          const parsed = JSON.parse(data);
          // Si es un array de items, lo sumamos
          if (Array.isArray(parsed)) {
            allFoundItems = [...allFoundItems, ...parsed];
          } 
          // Si es un objeto que contiene inventory, lo sumamos
          else if (parsed && parsed.inventory && Array.isArray(parsed.inventory)) {
            allFoundItems = [...allFoundItems, ...parsed.inventory];
          }
        } catch (e) {
          console.warn(`Aviso: Error menor al escanear clave: ${key}`);
        }
      }
    });

    if (allFoundItems.length === 0) return 0;

    // Fusión inteligente: Evitar duplicados por ID o por Serial
    const uniqueItems = new Map<string, any>();
    allFoundItems.forEach(item => {
      if (!item) return;
      const key = item.id || item.serial || `REC-${Math.random()}`;
      // Si el item ya existe, preferimos el que tenga más historial de mantenimiento
      if (uniqueItems.has(key)) {
        const existing = uniqueItems.get(key);
        const currentHistCount = (item.lifecycle?.maintenanceHistory?.length || 0);
        const existingHistCount = (existing.lifecycle?.maintenanceHistory?.length || 0);
        if (currentHistCount > existingHistCount) uniqueItems.set(key, item);
      } else {
        uniqueItems.set(key, item);
      }
    });

    // Normalización al esquema actual GxP
    const normalizedInventory: InventoryItem[] = Array.from(uniqueItems.values()).map(item => {
      // Detección automática de categoría para celulares/tablets si no la tiene
      let category = item.category || 'General';
      const name = (item.name || '').toLowerCase();
      if (name.includes('celular') || name.includes('iphone') || name.includes('telefono')) category = 'Celulares';
      else if (name.includes('tablet') || name.includes('ipad')) category = 'Tablets';
      else if (name.includes('compu') || name.includes('laptop') || name.includes('pc')) category = 'Computadores';

      return {
        id: item.id || `EQ-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
        name: item.name || 'Dispositivo Recuperado',
        category: category,
        model: item.model || item.marcaModelo || 'Modelo no especificado',
        serial: item.serial || 'Serial no registrado',
        assignedTo: item.assignedTo || item.responsable || 'Sin asignar',
        purchaseDate: item.purchaseDate || new Date().toISOString().split('T')[0],
        status: item.status || InventoryStatus.InUse,
        imageUrl: item.imageUrl || '',
        lifecycle: item.lifecycle || { 
          characteristics: item.characteristics || '', 
          maintenanceHistory: item.maintenanceHistory || item.history || [], 
          usageHistory: item.usageHistory || '', 
          observations: item.observations || '' 
        }
      };
    });

    setInventory(normalizedInventory);
    return normalizedInventory.length;
  }, []);

  // CARGA INICIAL Y ESCANEO AUTOMÁTICO
  useEffect(() => {
    const recoveredCount = performDeepDataRecovery();

    const savedSch = localStorage.getItem('vuelo_schedules');
    if (savedSch) {
      setAllSchedules(JSON.parse(savedSch));
    }

    if (recoveredCount > 0) {
      console.log(`%c VUELO PHARMA: Se han rescatado ${recoveredCount} equipos de sesiones anteriores.`, "color: #4B2E83; font-weight: bold; background: #00E5FF; padding: 4px; border-radius: 4px;");
    }
  }, [performDeepDataRecovery]);

  // SINCRONIZACIÓN MAESTRA (Efecto "Espejo" en tiempo real)
  useEffect(() => {
    if (inventory.length > 0) {
      localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
      // Buffer de seguridad extra para evitar pérdida por crash
      localStorage.setItem('vuelo_security_buffer', JSON.stringify({
        inventory,
        lastSync: new Date().toISOString()
      }));
    }
    if (Object.keys(allSchedules).length > 0) {
      localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
    }
    localStorage.setItem('vuelo_users', JSON.stringify(users));
    if (currentUser) localStorage.setItem('vuelo_current_user', JSON.stringify(currentUser));
  }, [inventory, allSchedules, users, currentUser]);

  const handleGlobalSave = useCallback(() => {
    setSaveStatus('saving');
    try {
      // Fuerza el guardado de todo el estado actual
      localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
      localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
      localStorage.setItem('vuelo_users', JSON.stringify(users));

      // Feedback visual
      setTimeout(() => {
        setSaveStatus('saved');
        setTimeout(() => setSaveStatus('idle'), 2000);
      }, 800);
    } catch (e) {
      alert("Error: El almacenamiento local está lleno o bloqueado.");
      setSaveStatus('idle');
    }
  }, [inventory, allSchedules, users]);

  const handleExportBackup = () => {
    const data = {
      inventory,
      allSchedules,
      users,
      exportDate: new Date().toISOString(),
      version: "2.1.0-GxP"
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `RESPALDO_MAESTRO_VUELO_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.inventory && data.allSchedules) {
          setInventory(data.inventory);
          setAllSchedules(data.allSchedules);
          alert("Base de datos sincronizada y restaurada con éxito.");
        }
      } catch (err) {
        alert("Error: El archivo de respaldo no es válido.");
      }
    };
    reader.readAsText(file);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (user) setCurrentUser(user);
    else alert('Credenciales de calidad incorrectas.');
  };

  const handleLogout = () => {
    if(confirm("¿Confirmar cierre de sesión? Los datos locales permanecerán seguros.")) {
      setCurrentUser(null);
      localStorage.removeItem('vuelo_current_user');
    }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-950 via-slate-950 to-black">
        <div className="bg-white p-12 rounded-[4rem] shadow-2xl w-full max-w-md border border-white/5 animate-fadeIn">
          <div className="text-center mb-10">
            <Logo className="h-32 mx-auto" />
            <h2 className="text-2xl font-black text-indigo-950 mt-10 uppercase tracking-widest leading-none">Gestión de Activos</h2>
            <p className="text-[10px] text-cyan-500 font-black uppercase tracking-[0.5em] mt-3">Soporte Técnico GxP</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[9px] font-black text-slate-400 uppercase ml-4 tracking-widest">Credencial de Usuario</label>
              <input 
                type="text" 
                placeholder="USUARIO" 
                className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 outline-none font-black text-xs uppercase tracking-widest"
                value={loginForm.username}
                onChange={e => setLoginForm({...loginForm, username: e.target.value})}
                required
              />
            </div>
            <div className="space-y-2">
              <label className="text-[9px] font-black text-slate-400 uppercase ml-4 tracking-widest">Clave de Acceso</label>
              <input 
                type="password" 
                placeholder="CONTRASEÑA" 
                className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 outline-none font-black text-xs uppercase tracking-widest"
                value={loginForm.password}
                onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                required
              />
            </div>
            <button className="w-full py-6 bg-indigo-950 text-white font-black rounded-[2rem] uppercase tracking-[0.3em] shadow-2xl hover:bg-slate-900 hover:-translate-y-1 transition-all text-xs border-b-4 border-cyan-400">
              Validar e Ingresar
            </button>
          </form>
          <p className="text-center mt-8 text-[8px] font-bold text-slate-300 uppercase tracking-widest">© 2025 Vuelo Pharma Colombia - Calidad TI</p>
        </div>
      </div>
    );
  }

  const isAdmin = currentUser.role === UserRole.Admin;

  return (
    <div className="min-h-screen bg-slate-50 font-sans selection:bg-cyan-100 selection:text-cyan-900">
      <header className="bg-white shadow-sm border-b-2 border-indigo-950 px-8 py-5 flex justify-between items-center sticky top-0 z-50">
         <Logo className="h-16" />
         <div className="flex items-center gap-5">
            {isAdmin && (
              <button 
                onClick={handleGlobalSave}
                className={`flex items-center gap-3 px-8 py-4 rounded-[2rem] font-black text-[10px] uppercase tracking-widest transition-all shadow-xl ${
                  saveStatus === 'saving' ? 'bg-amber-500 text-white animate-pulse' :
                  saveStatus === 'saved' ? 'bg-emerald-600 text-white scale-105' : 'bg-indigo-950 text-white hover:bg-slate-900 active:scale-95'
                }`}
              >
                <div className={`w-2 h-2 rounded-full ${saveStatus === 'saved' ? 'bg-white' : 'bg-cyan-400 animate-ping'}`} />
                {saveStatus === 'saving' ? 'Sincronizando...' : saveStatus === 'saved' ? 'Sesión Protegida' : 'Guardado Maestro'}
              </button>
            )}
            <div className="text-right hidden lg:block border-l-2 pl-5 border-slate-100">
               <p className="text-xs font-black text-indigo-950 uppercase leading-none">{currentUser.username}</p>
               <p className="text-[9px] text-indigo-400 font-black uppercase mt-1.5 tracking-widest">{isAdmin ? 'ADMINISTRADOR DE CALIDAD' : 'CONSULTA DE ACTIVOS'}</p>
            </div>
            <button onClick={handleLogout} className="p-4 bg-rose-50 text-rose-600 rounded-full hover:bg-rose-600 hover:text-white transition-all shadow-sm">
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
            </button>
         </div>
      </header>

      <main className="p-10 container mx-auto pb-32">
        <nav className="flex flex-wrap gap-3 mb-12 bg-white p-4 rounded-[3rem] border border-slate-100 shadow-sm overflow-x-auto no-scrollbar">
           <TabBtn active={activeTab === 'inventory'} label="Inventario General" onClick={() => setActiveTab('inventory')} />
           <TabBtn active={activeTab === 'schedule'} label="Programa Anual" onClick={() => setActiveTab('schedule')} />
           <TabBtn active={activeTab === 'indicators'} label="Indicadores" onClick={() => setActiveTab('indicators')} />
           <TabBtn active={activeTab === 'history'} label="Trazabilidad RAD-06" onClick={() => setActiveTab('history')} />
           {isAdmin && <TabBtn active={activeTab === 'record'} label="Registrar Intervención" onClick={() => setActiveTab('record')} />}
           {isAdmin && <TabBtn active={activeTab === 'users'} label="Sistema y Respaldos" onClick={() => setActiveTab('users')} />}
        </nav>

        <div className="animate-fadeIn">
          {activeTab === 'inventory' && <InventoryPanel inventory={inventory} setInventory={setInventory} readOnly={!isAdmin} />}
          {activeTab === 'schedule' && (
             <MaintenanceSchedule 
                schedule={allSchedules[selectedYear] || []} 
                setSchedule={(s) => setAllSchedules({...allSchedules, [selectedYear]: typeof s === 'function' ? s(allSchedules[selectedYear] || []) : s})}
                inventory={inventory}
                selectedYear={selectedYear}
                setSelectedYear={setSelectedYear}
                readOnly={!isAdmin}
             />
          )}
          {activeTab === 'indicators' && <IndicatorsPanel inventory={inventory} schedule={allSchedules[selectedYear] || []} />}
          {activeTab === 'history' && <HistoryPanel inventory={inventory} />}
          {isAdmin && activeTab === 'record' && (
             <MaintenanceRecord inventory={inventory} addMaintenanceToHistory={(id, h) => {
                setInventory(prev => prev.map(i => i.id === id ? {...i, lifecycle: {...i.lifecycle, maintenanceHistory: [...i.lifecycle.maintenanceHistory, h]}} : i));
                alert("Mantenimiento registrado y vinculado a la Hoja de Vida.");
             }} />
          )}
          {isAdmin && activeTab === 'users' && (
            <div className="space-y-10">
              <div className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm">
                 <h2 className="text-2xl font-black text-indigo-950 uppercase mb-10 flex items-center gap-4">
                   <div className="w-10 h-10 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600">
                     <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                   </div>
                   Control de Accesos
                 </h2>
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {users.map(u => (
                      <div key={u.id} className="p-8 bg-slate-50 rounded-[2.5rem] flex justify-between items-center border border-slate-100 group hover:border-indigo-200 transition-all">
                         <div>
                            <p className="font-black text-indigo-950 uppercase text-sm tracking-widest">{u.username}</p>
                            <p className="text-[10px] text-cyan-500 font-bold uppercase mt-2 tracking-widest">{u.role}</p>
                         </div>
                         {u.username !== currentUser.username && (
                           <button className="p-3 text-rose-300 hover:text-rose-600 transition-colors" onClick={() => setUsers(users.filter(usr => usr.id !== u.id))}>
                              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                           </button>
                         )}
                      </div>
                    ))}
                    <button className="p-8 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 font-black uppercase text-[10px] tracking-widest hover:bg-indigo-50 hover:border-indigo-300 transition-all flex flex-col items-center gap-3 justify-center" onClick={() => {
                      const name = prompt('Nombre de Usuario:');
                      const pass = prompt('Clave GxP:');
                      if(name && pass) setUsers([...users, { id: Date.now().toString(), username: name, password: pass, role: UserRole.Viewer }]);
                    }}>
                      <span className="text-2xl">+</span>
                      Crear Nueva Cuenta
                    </button>
                 </div>
              </div>

              <div className="bg-indigo-950 p-12 rounded-[4rem] border border-white/5 shadow-2xl relative overflow-hidden group">
                 <div className="absolute top-0 right-0 w-64 h-64 bg-cyan-400/10 rounded-full -mr-20 -mt-20 blur-3xl group-hover:bg-cyan-400/20 transition-all" />
                 <h2 className="text-2xl font-black text-white uppercase mb-4 flex items-center gap-4 relative z-10">
                   <svg className="w-8 h-8 text-cyan-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                   Gestión de Datos y Recuperación GxP
                 </h2>
                 <p className="text-xs text-indigo-300 font-bold mb-10 uppercase tracking-widest relative z-10">Utiliza estas herramientas para rescatar inventarios de celulares, tablets y computadores de días anteriores.</p>

                 <div className="flex flex-wrap gap-6 relative z-10">
                    <button onClick={performDeepDataRecovery} className="flex-1 min-w-[280px] p-8 bg-cyan-500 text-white rounded-[2.5rem] shadow-xl hover:-translate-y-1 transition-all flex flex-col items-center gap-3 border-b-4 border-cyan-700">
                       <span className="text-[11px] font-black uppercase tracking-[0.2em]">Escaneo Profundo de Memoria</span>
                       <span className="text-[8px] opacity-80 font-bold uppercase">(Busca registros de celulares y tablets antiguos)</span>
                    </button>

                    <button onClick={handleExportBackup} className="flex-1 min-w-[280px] p-8 bg-white text-indigo-950 rounded-[2.5rem] shadow-xl hover:-translate-y-1 transition-all flex flex-col items-center gap-3 border-b-4 border-slate-200">
                       <span className="text-[11px] font-black uppercase tracking-[0.2em]">Exportar Respaldo Maestro</span>
                       <span className="text-[8px] opacity-60 font-bold uppercase text-indigo-500">(Archivo JSON - Guardado Externo)</span>
                    </button>

                    <label className="flex-1 min-w-[280px] p-8 bg-indigo-900 border-2 border-indigo-700 text-white rounded-[2.5rem] shadow-lg hover:bg-indigo-800 transition-all flex flex-col items-center gap-3 cursor-pointer text-center">
                       <input type="file" className="hidden" accept=".json" onChange={handleImportBackup} />
                       <span className="text-[11px] font-black uppercase tracking-[0.2em]">Restaurar desde Archivo</span>
                       <span className="text-[8px] opacity-50 font-bold uppercase">(Cargar base de datos JSON)</span>
                    </label>
                 </div>
              </div>
            </div>
          )}
        </div>
      </main>
      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }
        .animate-fadeIn { animation: fadeIn 0.5s cubic-bezier(0.2, 1, 0.3, 1); }
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #E2E8F0; border-radius: 10px; }
      `}</style>
    </div>
  );
};

const TabBtn = ({ active, label, onClick }: any) => (
  <button 
    onClick={onClick} 
    className={`px-10 py-5 rounded-[2rem] font-black text-[10px] uppercase tracking-[0.25em] transition-all whitespace-nowrap ${
      active ? 'bg-indigo-950 text-white shadow-2xl scale-105 border-b-4 border-cyan-400' : 'text-slate-400 hover:text-indigo-950 hover:bg-indigo-50/50'
    }`}
  >
    {label}
  </button>
);

export default App;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import Logo from './components/Logo';
import MaintenanceRecord from './components/MaintenanceRecord';
import MaintenanceSchedule from './components/MaintenanceSchedule';
import InventoryPanel from './components/InventoryPanel';
import HistoryPanel from './components/HistoryPanel';
import IndicatorsPanel from './components/IndicatorsPanel';
import { InventoryItem, InventoryStatus, ScheduleEntry, User, UserRole } from './types';

const INITIAL_USERS: User[] = [
  { id: '1', username: 'areati', password: 'Vuelopharma2026*', role: UserRole.Admin },
  { id: '2', username: 'administrativos', password: 'Vuelopharma2026*', role: UserRole.Viewer }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('inventory');
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('vuelo_current_user');
    return saved ? JSON.parse(saved) : null;
  });
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('vuelo_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });

  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [selectedYear, setSelectedYear] = useState<string>(new Date().getFullYear().toString());

  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [allSchedules, setAllSchedules] = useState<Record<string, ScheduleEntry[]>>({});
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');
  const [hasLegacyData, setHasLegacyData] = useState(false);

  /**
   * MOTOR DE RECUPERACIÓN FORENSE GxP
   * Escanea el localStorage buscando cualquier estructura que parezca inventario.
   */
  const performDeepDataRecovery = useCallback((isManual = false) => {
    const legacyKeys = [
      'vuelo_inventory', 'inventory', 'items', 'equipos', 'inventory_items', 
      'vuelo_items', 'vuelo_data_backup', 'quality_manager_data', 'vuelo_security_buffer'
    ];

    let allFoundItems: any[] = [];

    // 1. Escaneo por Claves Conocidas
    legacyKeys.forEach(key => {
      const data = localStorage.getItem(key);
      if (data) {
        try {
          const parsed = JSON.parse(data);
          if (Array.isArray(parsed)) allFoundItems = [...allFoundItems, ...parsed];
          else if (parsed && parsed.inventory) allFoundItems = [...allFoundItems, ...parsed.inventory];
        } catch (e) {}
      }
    });

    // 2. Escaneo Global de Emergencia (Si es manual)
    if (isManual || allFoundItems.length === 0) {
      for (let i = 0; i < localStorage.length; i++) {
        const key = localStorage.key(i);
        if (key && !legacyKeys.includes(key)) {
          const data = localStorage.getItem(key);
          if (data && (data.includes('serial') || data.includes('maintenanceHistory'))) {
            try {
              const parsed = JSON.parse(data);
              if (Array.isArray(parsed)) allFoundItems = [...allFoundItems, ...parsed];
            } catch (e) {}
          }
        }
      }
    }

    if (allFoundItems.length === 0) return 0;

    // 3. Fusión y Limpieza (Unificar Celulares, Tablets y Computadores)
    const uniqueItems = new Map<string, any>();
    allFoundItems.forEach(item => {
      if (!item || (!item.id && !item.name)) return;
      const key = item.id || item.serial || `REC-${item.name}-${Math.random()}`;

      // Priorizar el item con más historial de mantenimiento
      if (uniqueItems.has(key)) {
        const existing = uniqueItems.get(key);
        const currentHist = item.lifecycle?.maintenanceHistory?.length || 0;
        const existingHist = existing.lifecycle?.maintenanceHistory?.length || 0;
        if (currentHist > existingHist) uniqueItems.set(key, item);
      } else {
        uniqueItems.set(key, item);
      }
    });

    // 4. Normalización de Categorías TI
    const normalizedInventory: InventoryItem[] = Array.from(uniqueItems.values()).map(item => {
      let category = item.category || 'General';
      const name = (item.name || '').toLowerCase();
      if (name.includes('celular') || name.includes('iphone') || name.includes('teléfono')) category = 'Celulares';
      else if (name.includes('tablet') || name.includes('ipad') || name.includes('tab')) category = 'Tablets';
      else if (name.includes('compu') || name.includes('laptop') || name.includes('pc') || name.includes('desktop')) category = 'Computadores';

      return {
        id: item.id || `EQ-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
        name: item.name || 'Activo Recuperado',
        category: category,
        model: item.model || item.marcaModelo || 'N/A',
        serial: item.serial || 'N/A',
        assignedTo: item.assignedTo || item.responsable || 'Sin asignar',
        purchaseDate: item.purchaseDate || new Date().toISOString().split('T')[0],
        status: item.status || InventoryStatus.InUse,
        imageUrl: item.imageUrl || '',
        lifecycle: item.lifecycle || { 
          characteristics: item.characteristics || '', 
          maintenanceHistory: item.maintenanceHistory || item.history || [], 
          usageHistory: item.usageHistory || '', 
          observations: item.observations || '' 
        }
      };
    });

    if (normalizedInventory.length > 0) {
      setInventory(normalizedInventory);
      // Guardado preventivo inmediato
      localStorage.setItem('vuelo_inventory', JSON.stringify(normalizedInventory));
      return normalizedInventory.length;
    }
    return 0;
  }, []);

  // EFECTO DE CARGA Y VERIFICACIÓN DE INTEGRIDAD
  useEffect(() => {
    const count = performDeepDataRecovery();
    const savedSch = localStorage.getItem('vuelo_schedules');
    if (savedSch) setAllSchedules(JSON.parse(savedSch));

    // Si el inventario está vacío pero detectamos claves antiguas, avisar
    if (count === 0) {
      const potential = ['inventory', 'items', 'equipos'].some(k => !!localStorage.getItem(k));
      if (potential) setHasLegacyData(true);
    }
  }, [performDeepDataRecovery]);

  // SINCRONIZACIÓN MAESTRA EN TIEMPO REAL
  useEffect(() => {
    if (inventory.length > 0) {
      localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
      // Log de Calidad para trazabilidad de sesión
      localStorage.setItem('vuelo_last_sync', new Date().toISOString());
    }
    if (Object.keys(allSchedules).length > 0) {
      localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
    }
    localStorage.setItem('vuelo_users', JSON.stringify(users));
    if (currentUser) localStorage.setItem('vuelo_current_user', JSON.stringify(currentUser));
  }, [inventory, allSchedules, users, currentUser]);

  const handleGlobalSave = useCallback(() => {
    setSaveStatus('saving');
    try {
      localStorage.setItem('vuelo_inventory', JSON.stringify(inventory));
      localStorage.setItem('vuelo_schedules', JSON.stringify(allSchedules));
      localStorage.setItem('vuelo_users', JSON.stringify(users));

      setTimeout(() => {
        setSaveStatus('saved');
        setTimeout(() => setSaveStatus('idle'), 2000);
      }, 800);
    } catch (e) {
      alert("Error de Almacenamiento: Espacio insuficiente en el navegador.");
      setSaveStatus('idle');
    }
  }, [inventory, allSchedules, users]);

  const handleExportBackup = () => {
    const data = {
      inventory,
      allSchedules,
      users,
      timestamp: new Date().toISOString(),
      session: "Vuelo-Pharma-GxP-2025"
    };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `VUELO_PHARMA_FULL_BACKUP_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const handleImportBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.inventory && data.allSchedules) {
          setInventory(data.inventory);
          setAllSchedules(data.allSchedules);
          alert("Base de datos restaurada correctamente.");
        }
      } catch (err) {
        alert("Archivo de respaldo no compatible.");
      }
    };
    reader.readAsText(file);
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = users.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (user) setCurrentUser(user);
