  const syncMasterData = useCallback(() => {
    const keys = ['vuelo_inventory', 'vuelo_security_buffer', 'vuelo_data_backup', 'inventory', 'equipos'];
    let masterData: InventoryItem[] = [];

    for (const key of keys) {
      const stored = localStorage.getItem(key);
      if (stored) {
        try {
          const parsed = JSON.parse(stored);
          const data = Array.isArray(parsed) ? parsed : (parsed.inventory || []);
          if (data.length >= masterData.length) {
            masterData = data;
          }
        } catch (e) {}
      }
    }

    if (masterData.length > 0) {
      setInventory(masterData);
    }

    const schedules = localStorage.getItem('vuelo_schedules');
    if (schedules) {
      try {
        setAllSchedules(JSON.parse(schedules));
      } catch (e) {}
    }
