  const handleRestoreJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.inventory || data.allSchedules) {
          if (confirm("Se detectaron datos de respaldo. ¿Desea sobreescribir la información actual con este archivo?")) {
            if (data.inventory) setInventory(data.inventory);
            if (data.allSchedules) setAllSchedules(data.allSchedules);
            alert("Restauración exitosa. Los datos se han sincronizado.");
          }
        } else {
          alert("El archivo no contiene un formato de respaldo válido para Vuelo Pharma.");
        }
      } catch (err) {
        alert("Error al leer el archivo JSON. Verifique que sea un respaldo válido.");
      }
