            <input 
              type="text" 
              placeholder="USUARIO" 
              className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 outline-none font-black text-xs uppercase tracking-[0.2em]"
              value={loginForm.username}
              onChange={e => setLoginForm({...loginForm, username: e.target.value})}
              autoComplete="username"
              required
            />
            <input 
              type="password" 
              placeholder="CONTRASEÑA" 
              className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 outline-none font-black text-xs uppercase tracking-[0.2em]"
