                  saveStatus === 'saved' ? 'bg-emerald-600 text-white scale-105' : 'bg-indigo-950 text-white hover:bg-slate-900'
                }`}
              >
                {saveStatus === 'saving' ? 'Guardando...' : saveStatus === 'saved' ? 'Datos Asegurados' : 'Guardado Maestro'}
              </button>
            )}
            <div className="text-right hidden lg:block border-l-2 pl-5 border-slate-100 mr-4">
               <p className="text-xs font-black text-indigo-950 uppercase leading-none">{currentUser.username}</p>
               <p className="text-[9px] text-indigo-400 font-black uppercase mt-1.5 tracking-widest">{isAdmin ? 'MODO ADMINISTRADOR' : 'MODO CONSULTA GxP'}</p>
