                         </div>
                         Exportar JSON Maestro
                      </button>

                      <button onClick={() => restoreFileInputRef.current?.click()} className="p-8 bg-cyan-500 text-white rounded-[2.5rem] font-black text-[10px] uppercase tracking-widest shadow-xl transition-all hover:-translate-y-1 flex flex-col items-center gap-4 border-b-4 border-cyan-700">
                         <div className="p-4 bg-cyan-400 rounded-full">
                            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" /></svg>
                         </div>
                         Restaurar desde JSON
                      </button>
                      <input 
                        type="file" 
                        ref={restoreFileInputRef} 
                        className="hidden" 
