const INITIAL_USERS: User[] = [
  { id: '1', username: 'areati', password: 'Vuelopharma2026*', role: UserRole.Admin },
  { id: '2', username: 'administrativos', password: 'Vuelopharma2026*', role: UserRole.Viewer }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('inventory');
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('vuelo_current_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [inventory, setInventory] = useState<InventoryItem[]>([]);
  const [allSchedules, setAllSchedules] = useState<Record<string, ScheduleEntry[]>>({});
  const [selectedYear, setSelectedYear] = useState<string>(new Date().getFullYear().toString());
  const [loginForm, setLoginForm] = useState({ username: '', password: '' });
  const [syncStatus, setSyncStatus] = useState<'synced' | 'loading' | 'offline'>('offline');
  const [remoteUrl, setRemoteUrl] = useState(() => localStorage.getItem('vuelo_remote_sync_url') || '');

  const restoreFileInputRef = useRef<HTMLInputElement>(null);

  /**
   * MOTOR DE DATOS MAESTRO (DISPONIBILIDAD 100%)
   * Carga los datos desde LocalStorage y, si hay una URL remota, intenta actualizar.
   */
  const syncEngine = useCallback(async (forceRemote = false) => {
    setSyncStatus('loading');

    // 1. Cargar lo que ya tenemos localmente (Disponibilidad inmediata)
    const localInv = localStorage.getItem('vuelo_inventory_master');
    const localSch = localStorage.getItem('vuelo_schedules_master');

    if (localInv) setInventory(JSON.parse(localInv));
    if (localSch) setAllSchedules(JSON.parse(localSch));

    // 2. Intentar sincronización automática si existe URL o si es forzada
    const urlToFetch = remoteUrl || localStorage.getItem('vuelo_remote_sync_url');
    if (urlToFetch) {
      try {
        const response = await fetch(urlToFetch, { cache: 'no-cache' });
        if (response.ok) {
          const remoteData = await response.json();
          if (remoteData.inventory) {
            setInventory(remoteData.inventory);
            localStorage.setItem('vuelo_inventory_master', JSON.stringify(remoteData.inventory));
          }
          if (remoteData.allSchedules) {
            setAllSchedules(remoteData.allSchedules);
            localStorage.setItem('vuelo_schedules_master', JSON.stringify(remoteData.allSchedules));
          }
          setSyncStatus('synced');
          return;
        }
      } catch (e) {
        console.warn("Sincronización remota fallida, operando en modo local.");
      }
    }

    setSyncStatus(localInv ? 'synced' : 'offline');
  }, [remoteUrl]);

  // Sincronización inicial al montar
  useEffect(() => {
    syncEngine();
  }, [syncEngine]);

  // Persistencia automática para el Admin
  useEffect(() => {
    if (currentUser?.role === UserRole.Admin) {
      localStorage.setItem('vuelo_inventory_master', JSON.stringify(inventory));
      localStorage.setItem('vuelo_schedules_master', JSON.stringify(allSchedules));
    }
  }, [inventory, allSchedules, currentUser]);

  const handleLogout = () => {
    if (window.confirm("¿Finalizar sesión de consulta? Los datos maestros permanecerán en este equipo.")) {
      localStorage.removeItem('vuelo_current_user');
      setCurrentUser(null);
      setLoginForm({ username: '', password: '' });
      setActiveTab('inventory');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = INITIAL_USERS.find(u => u.username === loginForm.username && u.password === loginForm.password);
    if (user) {
      setCurrentUser(user);
      localStorage.setItem('vuelo_current_user', JSON.stringify(user));
      syncEngine(); // Sincronizar al entrar
    } else {
      alert('Acceso denegado. Verifique sus credenciales de Gestión de Calidad.');
    }
  };

  const handleRestoreJSON = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.inventory || data.allSchedules) {
          setInventory(data.inventory || []);
          setAllSchedules(data.allSchedules || {});
          localStorage.setItem('vuelo_inventory_master', JSON.stringify(data.inventory || []));
          localStorage.setItem('vuelo_schedules_master', JSON.stringify(data.allSchedules || {}));
          alert("Base de datos actualizada automáticamente.");
          setSyncStatus('synced');
        }
      } catch (err) {
        alert("Archivo inválido.");
      }
    };
    reader.readAsText(file);
    if (restoreFileInputRef.current) restoreFileInputRef.current.value = '';
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-indigo-950 flex items-center justify-center p-6 bg-[radial-gradient(circle_at_top_right,_var(--tw-gradient-stops))] from-indigo-900 via-slate-950 to-black">
