                            * {isAdmin ? "Pegue aquí la URL de su archivo JSON alojado en la nube." : "El administrador ha definido esta fuente para actualizaciones automáticas."}
                         </p>
                      </div>

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        {isAdmin && (
                           <button onClick={() => {
                              const data = { inventory, allSchedules, exportDate: new Date().toISOString() };
