          {activeTab === 'indicators' && <IndicatorsPanel inventory={inventory} schedule={allSchedules[selectedYear] || []} />}
          {activeTab === 'history' && <HistoryPanel inventory={inventory} />}
          {isAdmin && activeTab === 'record' && (
